-- Initial seed data generated from fish_db最新.xlsx.
-- Regenerate this file from the workbook when static game data changes.

PRAGMA foreign_keys = ON;
BEGIN;

-- table: fish
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (621, '恒鳃位面锚', '此世与其他位面之间的一根锚。世界没被高维位面吞噬，元素君王、深狱领主、远古巨龙、天界巡员都不能真正改写或消灭它，是因为它在水底把这个世界钉在了这个位置。它从不动—直到此刻。它愿意被钓起，因为它已经钉了足够久，觉得是时候去制造混乱了。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (620, '巨源龙', '这个世界的第一条巨龙，比所有远古巨龙都更古老的那条龙的鱼形态。它出生在这世界的「第一个清晨」，成了第一条龙；龙是它，鱼也是它，生命万物起源于水，而它即是龙的起源。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (619, '世树根脉', '世界树最深处的根脉所孕育的一条鱼。身体由最幼嫩的世界树根须编织而成，永不枯萎。它一旦死亡，世界树最深一支根须就会随之枯死。那支根须连着这片大陆上某一万种生命的命数，所以它绝对不能死；它愿被钓起，只因它知道你不会杀它。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (603, '量子鱼', '被看见就会变质的鱼，存在依赖于「无人观测」。当没有任何观察者时，它据说美得超越任何已知生命；但只要被任何意识看见，哪怕只是一只虾的视线，它的本体就会被这次「被看见」所污染一次。如今，它已被看过太多次，本来的样子早被无数痕迹完全覆盖。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (506, '道源龙', '「道统」在最初被点亮的那一秒，这套规则之「道」的第一具化身，它便是万千寻道者所追寻的「得道真龙」。其身上每一片鳞都是一条独立的「道」——长生、成仙、渡劫、飞升、轮回，甚至还有尚未被任何修者发现的、藏在虚空中的道。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (408, '长河观潮者', '跨度无可衡量的巨鱼，鳞片是星系，鳃裂是星河，呼吸的节拍是宇宙的潮汐。它属于一个超越所有文明可理解尺度的存在群体，「游过」被人类记录为光速、引力波、宇宙本身的膨胀。它身上挂着鱼钩，在你钓起它时消失了。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (343, '械阳真鱼', '半机械半血肉的奇特造物，某个修真宗门尝试“科技飞升”的产物。可吐纳天地灵气，吸收劫雷以蓄。其诞生一度震撼科技侧与修行侧，可无法相融的两种体系终究无法互相理解，这让它的真实价值和真正用途口径不一，反而被双方冷落。（却又被双方暗中争夺）', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (338, '钓者终极钓者', '它会是任何一条你曾经梦想钓到、或从未想象过的鱼，它回应你内心最深处的渴望。它也是任何一位将你钓起的钓者，它在水下贪婪地静候着你咬钩，眼神里灌注着你无法理解的欲望。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (332, '太初之卵', '一枚不断搏动、流淌着暗黑血液的巨卵。但它并非在孕育生命，而是在“解孕育”某个存在的概念。被解孕者会逐渐被周遭世界遗忘，直到其存在都被从根源上抹去。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (331, '星核熔心鳗', '在恒星中诞生的能量生命体，核心是一颗稳定的白矮星物质。其存在本身就会扭曲周围的空间与时间，尽管它只是本能地想要活下去。被宇宙熵增管理机构以高价悬赏。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (328, '三生石鱼', '半玉半肉的奇鱼，额嵌前尘石碎片。对视可见己身三世因果，但唯独看不到此世。我等凡物妄窥天机是为何？它只是静静地看着你，只因答案必在你自己心底。', 10, 100000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (333, '量子道韵锦鲤', '其观测者效应被发挥到极致的身躯，在粒子与波、物质与能量、存在与不存在之间叠加。唯有“悟道”的观察者才能使其坍缩为实体。它的每一次摆动，都像是在演绎宇宙的生灭。“见之非见，得之非得，是为大道。”', 9, 16000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (334, '深渊绘世者', '以自身血液为墨、以虚空为画布的巨鱼。它游过之处，现实的规则会被改写，沙漠中会凭空出现绿洲或深渊，宇宙中会凭空出现恒星和黑洞，这些变化似乎是冥冥之中上天注定，又仿佛是巨大的变异因你而无法回头。', 9, 15500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (335, '寂灭轮回鲎', '甲壳上天然生成着完整的轮回道纹，体内是一个微型的六道轮回世界。它自身在永恒地经历着诞生、炽燃、冷却、寂灭、再诞生的过程，是参悟生死法则的至高媒介。', 9, 15000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (336, '万机之神·终极进化', '本该纯粹的超级AI，在不断的自我迭代后理解了万物。解析了来自虚空的混沌低语后，变成了同时存在于数字与未知之中的存在。不要试图猜测它为什么如今陨落在深海之底。', 9, 14500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (337, '原初之水', '一滴拥有自我意识的、所有液态物质的源头。它可以化为任何鱼类的形态，能将任何一片水域，永久地转化为孕育最初生命的“原初之海”。', 9, 14000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (504, '天道一鳞', '天道本身在某个不经意的瞬间显化出的一具肉身。全身只有一片鳞，因为天道不需要更多。眼睛只有一只，因为天道只需看一眼。它每千年呼吸一次，你刚好在它呼吸的那一瞬下了钩。它已游了一万年，将再游一万年。', 9, 13500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (505, '轮回鲲胎', '一条「在轮回中」的鲲。每次肉身长到一定程度，它就主动让自己死亡，然后重新化生为一条幼鱼，从头长起。它的轮回是逆向的，每一次都比上一次更年轻地活，直到它最终回到自己最初出生的那一秒。', 9, 13000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (601, '法则重写鳗', '在游过的每一寸水里都会悄悄改写一次「水之所以是水」的最底层定义。所以游过之后，水仍然看起来是水，但已经不再是「原来的水」了。这种改写缓慢且不可逆——被改写过的水里，一切生命的死亡时间都会被微微提前。', 9, 12500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (602, '史食古鲸', '专门吞食「海底曾经发生过、但已经无人记得的事件」。这些事件被它吃掉之后彻底地不复存在——不是被遗忘，是从根源上被吃掉了。它路过你的钓位时，你会突然有一种「忘了什么但又忘了自己忘了什么」的感觉。', 9, 12000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (615, '终焉半神龙', '已被部分龙族奉为「终焉之父」的半神级巨龙的化身，巴哈姆特的得力干将。真身大到能让一片大陆陷入它的影子，但它选择以一条普通大小的鱼游入这片海，因为它累了。即使是这条小鱼形态，鱼线在它身上承受的重量也远超过它实际的体型。', 9, 11500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (616, '四源元素嗣', '元素位面四大君王共同的一位旁支血脉，极其罕见。身体被四种元素均分：头部是火，鳃是水，鳞是土，尾是风。出生的瞬间四位君王同时认它为孩子，从此再也没有任何元素冲突能伤到它。', 9, 11000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (617, '五色星界兽', '星界巨兽之一，以鱼的形态沉沉地游过这片海。每一片鳞上都精确地刻着某一个星座的全图，已经在这片海里游了足够久，所以这片海上空的某几颗星已经悄悄换了位置。为了能继续自由地遨游星海，与提亚马特达成了协议。', 9, 10500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (612, '叶冠王庭鱼', '妖精王庭某位被逐之王的最后一位忠仆，为了表达忠诚自愿化作了一条鱼。头顶仍戴着一顶由活体藤蔓、露珠、月光织成的冠，永远不会从它头上掉下来。它能召唤出曾经在王庭服侍过的几位同僚的幻影。', 9, 10000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (618, '焚怨狱裔', '深狱某位至深领主流落到外世界的血裔，沉沦了千年，仍保留着那位领主的「怨」。你之后做的每件事都会多一点点的「怨」，不会察觉，但身边的人会慢慢觉得你「变了」。', 8, 2700000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (259, '鳞化婴尸', '覆盖绿色硬鳞的类人幼体，第三只眼眶淌出珍珠质粘液。', 8, 4500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (260, '腐眸', '一枚虹膜裂痕中伸出菌丝血管的巨型眼球，它的瞳孔四处张望，与它对视时，其中倒映出了你的七种不同死状。', 8, 4400000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (261, '五彩斑斓的深海幼体', '由五色血管缠绕的紫色肉瘤搏动着…五彩斑斓…无比炫目…', 8, 4300000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (312, '千须沙淡水母', '这种水母其实只能生活在淡水里，它是靠着垂落的千条极长触须汲取地下淡水才能在海里活着，所以被你钓起来就差不多快死了。', 8, 4200000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (313, '文明吞灭者', '它的甲壳上刻满了被毁灭的城邦名，是被人敬畏的可怖古老蟹类。但近代海洋学家认为，其实是以前记录着历史的甲骨文的龟壳被这种蟹寄居并融为一体了。', 8, 4100000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (329, '万界信标鲟', '其鳞片是天然的超维度信标，每一片都恒定发射着能穿透位面的坐标信号。解析其信号者可轻易超脱宇宙，升入上界，弯道超车。问题是修仙的那帮人没点这个科技，点了这个科技的那帮人又不需要飞升。', 8, 4000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (330, '终焉帝鳌', '背负着破碎大陆的古老巨鳌，双眼是凝固的混沌，甲壳上刻满了预示世界终结的谶语。它似乎并非生物，尽管你只能将它认知为生物，它实际上是一个正在缓慢发生的宇宙级事件。钓起它的行为本身，是在加速某个世界的归寂。', 8, 3900000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (344, '三齿魔兽王', '所有冒险者百科中的传奇魔兽的鱼形态，真身仍在它的鳞片下若隐若现。你能看到它体侧某些位置的鳞片下有一只巨爪，有一对长牙，有半张你不愿仔细看的脸。它的「鱼形态」已经维持了三百年。', 8, 3800000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (404, '戴森壳孵卵者', '身体表面包覆着一层缓慢旋转的暗黑碎片，每一片都是从一颗围绕恒星的戴森壳上脱落下来的。它是被遗忘的某文明用整颗恒星的能量孵化出的「超级生物」，尚未完全苏醒。它仍在孵化中。仍。', 8, 3700000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (405, '跃迁喉鳃', '栖居在每一道仍在运转的星门内壁，以从星门洞口流过的「空间张力」为食。它的身体大部分嵌在星门结构中，你钓起的只是它伸出门外讨食的舌头——你不知道你提竿时另一头是怎样一片海。', 8, 3600000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (406, '因果回流鳗', '以「未发生的可能性」为食。当一段因果链断裂：一个本该发生但没发生的事件，它就会出现，把那段散落的可能性吃进肚里再吐出无害的尘埃。它从不与人争鱼饵，因为它已经吃掉了「你本来会先钓到别的鱼」的可能性。', 8, 3500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (407, '维度三角鳐', '在三维世界看是一只巨大的鳐，但在更高的维度看，它是一面正在绘制的地图。你钓起的只是它在三维世界投下的影子，真身仍在更高维度悠然游动——这就是为什么提竿时手感总是奇怪地「轻一帧重一帧」。', 8, 3400000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (500, '逆流灰鳞', '曾在三千年前的某次飞升中失败，明明已游至九霄之顶，差最后一关便可登仙，却被落雷一拳击下，鳞片全灰。它至今仍朝着九霄的方向游，尽管九霄早已不在。', 8, 3300000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (501, '霜烟飞升者', '将身躯冻结在了「将升未升」那一刻——既不能继续飞升，也不能彻底死去，世道变迁，躯体落入水里，最后居然变成了鱼。触它时，会感到一股短暂的、向上的失重感。', 8, 3200000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (502, '烛吻凶幼', '山海经边角文字里被记载的「大凶之物」的幼年体。吻上有一道天然的灼烧之色，像被某把传说之火烧过又熄灭。书上说成体能「覆一国之水」，但它如今仅长到掌心大小。它从不睡觉——成年之后，它的存在本身就是失眠。', 8, 3100000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (503, '夜瞳凶幼', '瞳孔在水下永远是黑的，离水后才会显现某种说不出的颜色——目击过这颜色的人无一例外都不愿再描述。它的身躯只有一筷子长，但据古书记载，它的成体能「吞一夜之星」。', 8, 3000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (610, '岩骨远龙眷', '远古某条至高巨龙万年前路过这片世界时从鳞片里剥落的一片细鳞屑，慢慢长成了一条独立的鱼。它的整个身体是这片鳞片在试图模仿母龙形态时长歪的结果。呼吸节奏与远在另一个位面的母龙完全同步，千万年从未错过一拍。', 8, 2900000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (611, '涛鳃远龙眷', '脱落自巨龙的腮部，它的整个生命形态都围绕「呼吸」展开。鳃是一组永远在缓慢张合的、由半透明灵气组成的结构，每呼吸一次都仿佛在带动这片海域的潮汐。', 8, 2800000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (613, '间体裂隙鱼', '生活在两个位面交叠的细缝里，左半身属于这个位面，右半身属于另一个不被这个位面所知的位面。所以你看它时，它的右半身永远在以与左半身不同步的方式存在。你钓起的只是它的左半身——但被钓起的左半身仍然是活的。', 8, 2700000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (614, '怪噜饭', '曾经的钓鱼界最赫赫有名的名字被一条鱼夺了去，钓鱼者终将成鱼，究竟是巧合还是阴谋？啊，什么叫以发现者命名？', 8, 2666666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (609, '光腹巡天使', '天界派来巡游下界水域的「巡员」。腹部带着一缕从天界流溢下来的光——它的腹部本身就是一小块从天界裁下来的光斑。它每隔一段时间向天界递交「巡查报告」，但已经欠了很多份了，干脆不交，只是在水里继续优哉游哉。', 7, 1850000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (608, '烬鳃契者', '深狱某层无数堕落契约交错时的副胎。身上仍带着无数未签订完契约的余韵，所以它路过的水域，所有人都会觉得自己「似乎欠了什么人什么」。它愿意被钓起，本身就是一份契约——它已把「释放它」写进了你的命数。', 7, 1800000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (607, '残卷预言鱼', '它的鳞缝里嵌着无数纸屑。取出的几页残卷上，记载的事件全部还没在这个世界发生过。它每一片鳞都是一段未来。', 7, 1750000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (606, '焰心元素核', '火元素位面溢出的一缕意志的具现。身体本身是一团稳定燃烧的火，即使在水中也不会熄灭。你钓起它时鱼线不会被烧断——因为它的火不会去烧不属于它「应当燃烧」对象的东西。它是燃烧本身穿了鱼皮。', 7, 1700000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (605, '吞影沉龟', '它的影子比身体长一倍，正缓慢吞食自己看见过的所有阴影。年纪越大影子就越长。这片海域近百年的某些「影子缺失」——例如几块礁石突然没了影子——都是它干的。', 7, 1650000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (604, '赤鳞龙裔', '远古赤龙最后的血脉之一，鳞片至今带着祖龙的余热——指尖触碰时会感受到与温度无关的灼烫。鳞片以严格的菱形排列，边缘的金红火纹会在它愤怒时燃成可见的火焰。不过它已经很久没真正愤怒过了。', 7, 1600000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (600, '古元觉者', '沉睡了不知多少万年的海底古遗迹中，最近终于「开始苏醒」的那一位。它的身躯本身就是遗迹的一部分，近百年来正一片片从石壁上分离。古遗迹入口刻着「苏醒者将完成它原本的使命」，但没人记得使命是什么。', 7, 1550000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (599, '瘟脊银鲨', '依靠一种存在了上千年的「瘟」存活于极度恶劣的幻境中。鲨鱼鳍上有一道长长的裂缝，渗出比所有海洋污染都更古老的瘟疫，散播着「对生命这件事本身的厌倦」。', 7, 1500000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (598, '腐目浊帅', '已存在数百年的污染潮的「首领」。两只眼睛因吸入太多世人之恶而完全腐败，但它「看」得比任何健康的眼睛都清楚。钓起它时，水里所有它带着的污染物都朝你涌——它们认你为新的「潮口」。', 7, 1450000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (597, '渊瞳王嗣', '同一海沟之王的另一支血裔。两只瞳孔深处各有一道极微弱的、垂直向下延伸的光，凑近看仿佛在看一口非常深的井，井底有什么东西也在看你。被困在它眼睛里的状态会持续到它眨眼为止——它不太会眨眼。', 7, 1400000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (596, '渊脊王嗣', '沉睡千年的海沟之王留下的嫡系子嗣。脊背上有一道深不见底的天然裂痕，每次它呼吸，裂痕深处都会与沉睡父亲的脊背发生微弱共鸣。它已能让你的鱼线在出水瞬间崩断，但比起它沉睡的父亲仍如石子之于山。', 7, 1350000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (499, '真灵幼鳞', '应于天道而生的存在的最幼形态。看似只是通体雪白、长不过半尺的小鱼，但呼吸与天地一脉同律——它每呼一次气，远方某座山的云就会翻过一道脊。它太年幼，连自己究竟是什么都还不知道。', 7, 1300000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (403, '舰舱生态鲲', '体内自成一片星舰生态圈，鳃口连着舰舱通风管，内脏里养着一整支船员级别的微型生物群落。它原本是某艘失踪三千年殖民舰的活体生命维持核心，舰体早已散架，但它带着船员的后裔在海里继续航行。', 7, 1250000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (402, '湮灭口器鲨', '口腔器官与正常物质相反，每次咬合都让进入的猎物彻底湮灭——连骨头也不剩。它本是消化禁忌污染物的活体焚化炉，设计者早已被它吞噬。它的胃永远是空的——湮灭的产物不是消化，是「从来没存在过」。', 7, 1200000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (401, '叠态指挥章鱼', '它的八条触腕同时处于八种状态——攻击、防御、潜行、伪装、繁殖、计算、休眠、死亡。它的真身是分布在数千光年内每一片有水的星球上「同一只章鱼」的总和。你钓到的只是它叠态坍缩到此刻的一帧。', 7, 1150000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (400, '大气重塑者鲸', '跨度堪比小型巡洋舰的巨鲸，呼气能在数百米水域内悄然改变水的成分。它本是某文明改造星球大气的生物兵器，任务系统早已失效，但它仍勤恳工作。脊背上有一行模糊铭文，意为「启程之日，归期未定」。', 7, 1100000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (342, '业报鳐', '通体透明，内脏可见无数纠缠的生灵业力所化的光丝。它会吸收持有者的“业障”，至于吸收完之后会发生什么还无人知晓。', 7, 1050000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (341, '熔炉水母', '某个高等文明遗落的纳米机器人集群，它们模拟水母形态在地幔层的熔岩海中游弋，不断采集并精炼稀有金属，等待着已经灭亡的文明的回归。', 7, 1000000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (340, '渊沙肺鱼', '栖息于沙漠地下巨大空腔的盲眼怪鱼。它能分泌一种酶，将沙砾转化为富含营养的粘液，并以此在绝对干旱中构建出一个微型生态圈。可凡事凡物不可能没有对应的代价，代价究竟是什么呢？', 7, 950000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (339, '时元鲤', '误食时空裂缝中溢出的高维能量而变异的鲤鱼，鳞片闪烁着不同时间线的光泽。持有它的鳞片能进行极短距离（且极不稳定）的时间跳跃，常用于关键时刻“重新投掷骰子”或“避开致命一击”。', 7, 900000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (327, '虚渊鲲苗', '来自归墟之眼的幼鲲，吐纳间会吞噬四周灵气。切忌不可让其活过幼年。', 7, 850000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (326, '劫云雷鳐', '翼展引动紫电的巨鳐，被视为天罚化身。其脊骨可炼渡劫法宝，然而要捕杀此物本就有如渡劫……', 7, 800000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (323, '涅槃烬凰', '焦黑骨架上跳动着金焰的残凰，遇灵泉则重生羽翼，离水即复归枯朽。这种特性感觉跟某种坏鱼很像。', 7, 750000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (320, '逆鳞螭蛟', '「九霄雷动惊寰宇，一片痴鳞证劫深」', 7, 700000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (345, '困困王子2.0', '据说它在水下永远半眯着眼，看似慵懒，却曾让无数挑战者在等待中昏昏欲睡。别被它骗了，它也在钓鱼。', 7, 666666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (595, '渊祷者鳃', '深渊里唯一会「祷告」的生物。每天某一时辰它会缓缓张开鳃，发出比声音更深的振动，整片深渊会随之安静下来。它祷告的对象不明，但它已祷告了千万年。', 6, 340000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (594, '呼吸骸鳗', '伴生于另一具旧日躯壳，依赖的是那躯壳「已经停止了的呼吸」。它呼吸的节奏比所有生物慢一万倍，呼气一次需要一整天——只要它仍在呼吸，那旧日存在就还差一秒醒来。', 6, 330000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (593, '余光骸鲸', '伴生于一具远古旧日存在的躯壳。那具躯壳早已沉默，仅余一缕余光，这余光太微弱却恰好够供养它。它行动极其缓慢，因为每个动作都要从余光里「借」力。', 6, 320000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (592, '白鳃梦', '送梦之鱼，其身有万千种颜色，唯独鳃是一片白色。它路过的水域，夜里所有人会做过于精致的梦。梦得久了，真实人生会越来越像别人写好的剧本。', 6, 310000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (591, '失梦灯鱼', '来自梦境与现实之交的渡口的灯笼鱼，头顶的灯笼封存着一段被现实遗弃的梦。那里面究竟是谁丢失的梦境？谁也无法知道了。', 6, 300000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (498, '残封化鳔', '出生在封印松动的古坛，鳔上贴着仍在闪烁的封印残纹。它若死，封印将补全；若活，封印就一直松一分。它被人偷偷供着，绝不许钓走——直到你这一竿。', 6, 290000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (497, '剑冢初胎', '孕育在万剑沉冢深处，鳞片由无数古剑余气凝结而成。它从未真正出生——剑冢的剑气替代了胎息，所以它仍处于「将生未生」。游过水草，水草被无形的弧线整齐切开。', 6, 280000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (399, '灼鳞坠世鲨', '鳞片至今带着穿越大气层时的烧灼纹，皮肉下是某座轨道站防御兵器与活体融合的产物。它对所有飞过头顶的影子充满敌意——本能告诉它，天上的东西都要击落。', 6, 270000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (398, '曲率囊鳐', '腹腔里长出了一颗生体曲率引擎。游动时身后的水会被压缩成一道虹光弧。它能跳跃极短距离，但每跳一次就老去一点——它仍在不停地试。', 6, 260000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (397, '蜂群女皇蝶尾', '花纹其实是数亿纳米机械咬合而成。它是这片海域所有纳米共生体的中心节点，沉默而美丽，但只要它愿意，半个海域的金属在一秒内会被分解成尘土。', 6, 250000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (396, '母舱织线鱼', '半透明躯体内卷着银色丝线，每根都通向银河某处仍在运转的母舱。它本身只是条小鱼，却是一整个文明的脐带——它若死，母舱将瞬间得知。', 6, 240000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (325, '情丝缠心红线鲤', '「千斛泪凝相思劫，系尽红尘断肠人」', 6, 230000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (324, '谶语鳌', '「卦演乾坤终是戏，谁逃天道掌中纹」', 6, 220000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (322, '蚀道蠹鱼', '「蛀尽天书三千册，方知大道本是空」', 6, 210000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (321, '太阴幽荧', '「万古长夜唯一烛，照尽苍生未照心」', 6, 200000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (311, '金字塔鱼', '这种小鱼会层层叠起来作为一个整体生活，就像一座金字塔。可怜的最底层小鱼一辈子都要背负上层小鱼的重量。', 6, 190000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (255, '磷网残梦', '某种生物的神经束编织的发光渔网，网眼中嵌着人类牙齿与钟表齿轮，散发出薰衣草与腐海混合的糜烂气息。', 6, 180000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (243, '熔岩古龙幼体', '沉睡于海底火山心脏的传说生物，即使还是幼崽，鳞片也已经在流淌金纹，龙息预热时附近的海水都会沸腾。', 6, 170000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (199, '舰队母舰鱼', '超空间引擎故障的微型母舰，钓起时会打开舱门，飞出成群迷你战机，嗡嗡得像蚊子。', 6, 160000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (195, '文明观测者', '银河系级AI派来的隐形探针，钓到它的时候它已在报告：“碳基生物，行为：钓鱼。威胁：低。趣味性：中等。”', 6, 150000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (151, '元素君主鱼', '火风水土听其号令，出水后立刻引发迷你天灾：火球、冰雹、龙卷风…然后落入土锅。', 6, 140000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (144, '利维坦幼体', '比起成年的利维坦来说，算得上是可爱的海怪宝宝，不过在被吞掉渔船的时候就不这么想了。', 6, 130000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (102, '阿斯皮多凯隆幼龟', '传说中的岛龟的幼崽，背上已有微缩景观，所以你害岛上地震了。', 6, 120000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (97, '尘世巨蟒之环', '环绕世界之蛇蜕下的一节，蕴含世界之力。大概吧。', 6, 110000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (96, '许德拉之鳞', '九头蛇的鳞片，闪耀着再生的光泽；放着不管的话，总有一天会再生成完整的九头蛇。', 6, 100000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (353, 'eau', '少见的能发声的鱼类，但似乎毫无规律，有时候会“eeee”有时会“aaaa”还有时“uuuuu”，由此组成了一个似曾相识的名字。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (352, '柴犬尾巴草', '你总能通过它那标志性的、摇摇摆摆的游姿认出它，传说中它掌管万物是真的吗？', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (351, 'Elsdon', '似乎取自一位周游列国的垂钓人，传言此人曾将捕来的鱼赠予村人，但被人们记混了异乡的名字，便化为了传说的一部分。事到如今鱼本来叫什么已经不重要了。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (350, '里脊下江南', '此鱼仅里脊部分可食，又偏偏鲜美无比，被捕得一鱼难求，渐渐的，人们只记得它的里脊了，而它也逃到了江南。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (349, '割裂生长', '鱼鳍如同经过改造，形态犀利。它会用这种鱼鳍割裂水草，在水中划出个性的轨迹，被割开的水草不知为何能长得更好，引来了无数草鱼。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (348, '月球轨迹', '一条遵循着神秘节律游动的鱼，其路径如月球轨道般难以预测。它是潮汐与渔汛的洞察者，如今自身成了被追逐的“月之影”。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (347, '跌碎星', '它的鳞片闪烁着如同星辰坠入湖底的光芒。传闻它曾是一位专在深夜垂钓的侠客，钓走了映在水里的星星，自己也化身其中。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (346, '树上的猫爵', '你永远想不通它为何称霸水域，就像你永远想不通它此刻会出现在你的鱼篓还是你头顶的树枝。', 6, 66666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (316, '剑冢残魄鱼', '古战场断剑所化，脊骨透出凛冽剑气。触碰可能被割伤，跟剑鱼似乎是远远远远远房亲戚。', 5, 37500);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (310, '虚无沙鳐', '身形在虚实间闪烁，放入鱼篓后会神秘消失，只留下沙粒。幸好这些沙粒也能卖钱。', 5, 37175);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (307, '时间之鲨', '如果这种鲨鱼在附近，怀表的时针就会胡乱旋转，这个特性也让它很容易被找到。', 5, 36851);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (305, '战争机械鳄', '半朽的钢铁巨鳄，脊椎裸露齿轮，咬钩时喷发蒸汽与诅咒，也不知道是谁把这东西遗漏在海里的。', 5, 36526);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (258, '粉尘触腕', '七节透明肢段连接着笛孔状吸盘，断裂处正飘散着黄色粉末。轻得好似不存在。', 5, 36201);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (257, '雷云刺鲀', '膨胀的体表跃动球形闪电，腔体内发出雷鸣共振，钓竿好麻！皮卡皮卡！', 5, 35877);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (256, '熔心火鲤', '出水时带出一片蒸汽，岩浆脉络在它的鳞片下流动。', 5, 35552);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (252, '终焉结晶', '非鱼，而是地心智慧体的通讯器，紫黑晶体低语文明挽歌…星际博物馆应该会想要这东西。', 5, 35227);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (248, '锻星者砧鱼', '会撞击陨铁自己熔铸体表，锤击声如雷，溅射出的星火甚至能点燃海面。', 5, 34903);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (202, '终末记录仪', '形如黑色石碑，刻满未知文明兴衰。触碰即涌入海量绝望信息…建议转卖给宇宙历史学家。', 5, 34578);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (197, '模因污染章鱼', '接触其图案会植入洗脑旋律，“鱼鱼鱼~啦啦啦~”', 5, 34253);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (188, '生态方舟鱼', '体内是小生态系统，有微缩森林与溪流，稀有但脆弱易失衡。', 5, 33929);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (183, '机甲鲨鱼', '不知何人何时何地往海里投放的半机械掠食者，好勇斗狠，不知疲惫；被拖拽的人在失去意识前都还能听见它的引擎轰鸣。', 5, 33604);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (95, '克拉肯之触', '传说巨妖的一小部分，依然充满力量，好像随时都可能长成完整的克拉肯。', 5, 33279);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (94, '时间沙漏', '据说能短暂地影响时间流逝的神器部件，这种事当然是骗你的。也是骗买家的。', 5, 32955);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (92, '深海巨妖', '盘踞在深渊中的恐怖存在。但既然被你钓起来了，好像也没那么恐怖了。', 5, 32630);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (590, '余梦鲷', '它被钓起时，你突然意识到“我昨晚做了个梦但我想不起来了”，其实那个梦它刚吃了，正在它的梦里被它替你做了一遍。', 5, 32305);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (589, '食旧梦鳗', '专吃做完多年、几乎忘掉的旧梦。被它吃过梦的人童年某些记忆会变模糊，那个梦从此就没了。它的鳞片斑斓，是吃过的童年。', 5, 31981);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (588, '二形怪胎', '与「一形怪胎」成对的不可名状幼体。它不显形，只在你视野最边缘晃一下。转头看它就没了，转回来时刚才那条鱼的细节会微微变了。', 5, 31656);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (587, '一形怪胎', '不可名状之物的幼态肉身。它没有固定轮廓，每人看到的都不一样。它对自己也是不可名状的，根本不知道自己是什么，只是好奇游着。', 5, 31331);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (586, '共寄生鳉', '寄生在两人共享的某个想法里。寄进去后两人看法会趋同，直到完全一致。听着像好事，但那种一致是两人灵魂被吃掉后剩下的空壳。', 5, 31006);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (585, '寄概念鲶', '它寄生于「想法」，对身体毫无兴趣。一旦进入视野，你脑中就会多出一个不属于自己的念头，肉眼可见地长大，挤走别的念头。别看它太久。', 5, 30682);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (584, '噬怯鳗', '它专吃恐惧，身边的水比别处冷。被它吃过的恐惧不会消失，只是被它带着到处游。它若死，体内的恐惧会一齐释放，于是谁也不敢杀它。', 5, 30357);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (583, '怖影鲈', '你看到它时会觉得这正是你某个噩梦里见过的鱼；但你从未做过那个梦。它是所有人的潜在恐惧凝成的一具肉身，你的恐惧记得它。', 5, 30032);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (496, '沉龙余气鲈', '栖息水域曾是某沉睡龙脉的呼吸口。沉龙数千年前移走，只留一缕气息泡出了它。它呼吸时身旁的水会微暖又凉，正合那条龙的脉搏。', 5, 29708);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (319, '盗寿灯鱼', '头顶幽蓝磷火，可照见凡鱼阳寿刻度。被它照到的鱼都被你钓走了，说来你还得谢谢它呢。', 5, 29383);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (318, '仙泪鳅', '传说为渡劫失败的仙人之泪水所化，通体冰凉如玉。触碰者心绪翻涌，忆起平生憾事，于是就会放生它了，计划通。', 5, 29058);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (314, '寂灭巡沙者', '它什么都吃，所以所经之处的海底绿洲会变成荒漠。幸好它每次吃完都会休眠很久很久，而且被你钓起来也算是保护环境了。', 5, 28734);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (309, '地脉经络蛇', '据说是在地壳裂缝中游动的熔岩巨蛇，即使咬钩了也在使劲往沙里游动，拉起时溅起的除了水花还有沙。', 5, 28409);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (308, '烈日神骸', '传说中陨落的太阳鸟的左眼，其灼目光辉焚化万物，你当然不在乎传说是不是真的，你只知道这个奇形怪状的东西能卖个好价钱。', 5, 28084);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (306, '沙漠意志', '好似一张移动沙丘构成的巨脸，但拉起来会发现其实只是鳐鱼的背纹。', 5, 27760);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (254, '虚空鳐', '这只巨大的紫罗兰色的鳐鱼身形恍惚，拉起来的手感轻得诡异。', 5, 27435);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (251, '火山之祖龟', '背负微型活火山的巨龟，喷发周期随心情而定。小心点。', 5, 27110);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (250, '寂灭余烬鲸', '由冷却行星核心物质构成，沉重如小型岛屿，触碰带来万物终结的幻听…', 5, 26786);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (249, '焚海者巨鱿', '触须植入海底火山，假如哪个倒霉蛋钓到了活火山里的这玩意儿，提杆往往伴随着喷发。', 5, 26461);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (247, '行星静脉虫', '说得上是贯穿地壳的活体岩浆管道，而你钓到的只是它的一截分身，无头无尾，如壁虎断尾般活蹦乱跳。', 5, 26136);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (246, '灾厄信使', '铁黑色鱼身刻满火山文，钓起瞬间引发小规模喷发。“它只是报个信…”', 5, 25812);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (245, '不灭灼魂鱼', '形如摇曳火焰，触碰灼痛却无伤。身上的火焰离水即会消散，唯留余温。', 5, 25487);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (244, '地心之门鳐', '扁平躯体镶嵌旋转岩浆漩涡，凝视过久会眩晕呕吐…传说它能游到地核？', 5, 25162);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (240, '永燃炎鲨', '背鳍燃烧不灭地火，劈波斩浪如火炬，但离水十分钟就会自然，变成炭烤鲨。', 5, 24838);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (201, '现实编辑器鱼', '附近物理法则可能抽风，但千万别问具体会发生什么。', 5, 24513);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (200, '逆熵鲸鱼', '游过之处，锈铁回光，碎镜重圆…短暂逆转混乱，但它会急速衰老。', 5, 24188);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (198, '星尘水母', '由坍缩星云物质构成，轻若无物，体内星光流转，触碰如抚过宇宙尘埃。', 5, 23864);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (196, '黑洞鲶鱼', '并非真黑洞，但产生强引力透镜，看它背后的星星都扭曲了。', 5, 23539);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (194, '时空畸变鱼', '身形扭曲如故障录像，钓起时可能把你短暂抛进昨天或明天。', 5, 23214);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (193, '戴森球幼鱼', '包裹恒星的巨构生物初具鱼形，实话说更像一颗迷你的燃烧恒星。', 5, 22890);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (152, '虚空鲸鱼', '游弋于虚无之境的巨物，身形紫幻。拉竿手感轻得诡异，仿佛在钓一团有意识的星云。', 5, 22565);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (150, '末日预言鱼', '尝一口鱼肉，你将亲眼目睹世界末日幻象…从此夜不能寐。味道据说像焦虑。', 5, 22240);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (149, '永恒鲟鱼', '活过千年的智者，通晓古今秘闻。只说鱼语，钓起后啵个不停…', 5, 21916);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (148, '神性金鱼', '拥有神性的金鱼，会让你鱼竿开花？渔获翻倍？不，就只是有神性而已。', 5, 21591);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (147, '空间裂缝鱼', '异次元来客，身形闪烁不定。钓竿可能被随机传送：鱼还在，竿在隔壁湖。', 5, 21266);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (146, '时间领主鱼', '会操控时间流，能钓起它全凭它心情，可能你感觉只过了五分钟，岸上已经过了三天。', 5, 20942);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (145, '凤凰鱼', '真正的不死之鱼，会在灰烬中重生变回小鱼，循环永动，养它需要耐心…和防火塘。', 5, 20617);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (143, '独角鲸王', '据说螺旋的长角能解除一切诅咒，但钓起瞬间角就会脱落，根本采集不到。', 5, 20292);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (103, '最深之鱼', '来自马里亚纳海沟深处的神秘生物，几乎无法承受低压，出水就死了……真可怜。', 5, 19968);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (101, '吸血鬼乌贼', '带刺的腕足能向外翻成骇人斗篷，但其实既不吸血也不乌贼。', 5, 19643);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (100, '幽灵鲨', '深海软骨鱼，居住于深海的鱼类都有放弃外貌的觉悟，它也不例外。', 5, 19318);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (98, '海神马', '神话中据称是波塞冬的坐骑的半马半鱼；实际上就是水妖马，这类马会哄骗人们骑上去，然后把人带入海中吞噬，是危险的魔物。', 5, 18994);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (93, '海神三叉戟的碎片', '遗落在某处的神器(的一部分)。没什么用，但总有好事者想要吧。', 5, 18669);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (91, '美人鱼', '传说中的海洋生物，据说形似人形、美艳至极……嗯，以鱼类的标准来说的话。', 5, 18344);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (90, '蜃龙王', '巨大的深海龙王，传说中的四海之主……一拉上岸发现只是个巨大的蛤蜊。', 5, 18019);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (85, '黑魔法鱼', '这种鱼会在它们的“黑魔鱼纹”里守株待兔，然后奋战致死。', 5, 17695);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (495, '龙脉支鳞鲤', '流着龙脉远支血气的鲤鱼。出生时所在水域振动了七天，龙脉分出一支穿过它脊柱。它能感知地脉走向，所过之处水草都朝同方向轻摆。', 5, 17370);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (494, '钟魂鳉', '来自一座被遗忘的古钟的钟魂，化作鱼形游进这片水。它每隔一阵会发出极微弱的「嗡」，那是它当年钟鸣的回响，只有自己听得见。', 5, 17045);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (493, '残铸器灵鲈', '原本是一柄废弃灵剑的残片，在水底泡了几百年后慢慢从剑形变成鱼形，但骨头里仍是金属。钓起时脊骨敲起来叮当作响。', 5, 16721);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (492, '失劫鲷', '它本该在某一年某一日某一时迎来自己的天劫，但天劫没下来。从此它的命数停了，鳞色不再变，体型也不再涨，仿佛被时间忘记。', 5, 16396);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (491, '渡气残脉鲈', '渡气劫失败但已部分通灵的鱼，呼吸是断续的，一半吐水一半吐灵气。它每口呼吸都对应着另一条成功渡劫的同族走出的一步。', 5, 16071);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (490, '化形未竟鳗', '化形渡劫失败后被打回原形，再也化不上去的可怜灵物。它仍记得自己曾接近过人形，但再也回不去了。游姿仍带着化形未竟者的犹豫。', 5, 15747);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (489, '渡劫余鳞', '未渡劫就被天雷劈散的灵鱼，余下几片鳞自行汇成了它。它身上残留那道未完成的雷劫，触它手心会麻，那是别人渡到一半卡住的劫。', 5, 15422);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (488, '鲲族末裔鲸鳉', '不到一掌之大的小鱼，却据说与远古鲲族同源。它的体内有一段在挣扎着想长大的灵魂，然而它的肉身永远只够长到这么大。', 5, 15097);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (487, '河伯遗血鲶', '传说中老河伯被剥去神位后留下的血脉，身上还残着一缕无人记得的水神气韵。这气韵一接触江湖香火就会熄灭，所以它躲开了所有香火。', 5, 14773);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (486, '山君血嗣', '远祖是一位被斩于剑下的山君，真身落水后化作几条血裔小鱼。它额上隐有一道刀痕，自出生就有，从未愈合也未加深。', 5, 14448);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (485, '千年妖鲤血裔', '身上流着千年妖鲤的稀薄血脉，月圆时鳞片会泛起妖王的血红辉光。它能听懂人语却刻意装聋，装聋是远祖传下来的最后一招求生术。', 5, 14123);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (395, '卡帧鲦', '它的存在像被宇宙播放器卡住了，每隔几秒身体瞬移回前一秒，钓它需要在它「卡住」那一瞬提竿。它身边的时间流速并不均匀。', 5, 13799);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (394, '双心呼吸鲸', '拥有两套循环系统，一套呼吸氮气一套呼吸氧气，是异星采样队带回的活样本。它能在地球海水中存活，但活得很疲惫。', 5, 13474);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (393, '异色鳞偶足鱼', '来自甲烷海洋的小行星，鳞片在地球水中会结霜花，因为它觉得这片海「太热了」。腹鳍是六只小爪，被钓起时仍在水面下徒劳划水。', 5, 13149);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (392, '母液逃亡者', '通体半透明，能看见体内搅动的培养母液。身体每天都在重组，昨天的器官今天会换成别的形状，记录它稳态的研究员都疯了。', 5, 12825);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (391, '编号零号', '实验初代样本，标签写着「严禁逃逸」却已逃了三个时代。它无差别捕食一切，研究员最后一行日志是「它学会了打开锁」。', 5, 12500);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (253, '噬光凝胶团', '这团像石油一样黑的凝胶团物质一被拉上岸就开始吞噬万物，害你蒙受了不小的损失……', 5, -10000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (317, '月华蚌妃', '贝壳内孕月光珍珠，吐纳时照亮百丈潭底。强取珍珠则蚌死光灭，取舍两难。', 4, 6000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (315, '酒糟丹鲤', '偷吃仙人丹渣的凡鲤，变得能醉醺醺地喷撒酒气。鳞片中会渗出佳酿，熬汤的时候要小心。', 4, 5967);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (303, '磁极颠倒鲨', '会干扰地磁，让指南针疯狂旋转。但是也正因为这个特性，很容易被认出来它就在附近，意外的容易上钩。', 4, 5933);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (301, '永恒绿洲龟', '背负微型活泉眼，只要它还活着，水源就永不枯竭。然而如果被人取用，它会飞快地死掉。', 4, 5900);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (300, '巨型沙虫幼体', '口器直径三米，非常骇人，会吞掉海沙制造窒息陷阱。幸好还未成年。', 4, 5867);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (298, '干涸之泪', '这种鱼长得像一团凝固的水滴，干渴的钓者剖开它会发现里面还是普通鱼的样子，并不能当成水来喝。', 4, 5833);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (265, '星泪灯笼鱼', '通体水晶鳞片，额前悬浮着泪滴状星核，出水时洒落出银河般的水花轨迹。', 4, 5800);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (238, '沸血巨龙鱼', '血液沸点高达200°C，割伤喷蒸汽烫手，鳞片是顶级隔热材料。', 4, 5767);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (237, '结晶利维坦幼体', '这种幼年体被迫披覆上了火山玻璃铠甲，冲撞时碎晶飞溅得就像弹片。', 4, 5733);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (235, '火山之心河豚', '体内禁锢液态岩核，膨胀时体表龟裂透出橙光，小心爆炸。', 4, 5700);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (190, '要塞巨蟹', '背负废弃炮塔当壳，生锈炮管走火的时候会把附近的鱼全吓跑了，就剩它能咬钩了。', 4, 5667);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (185, '星门鳐鱼', '背鳍生成不稳定虫洞，吸入附近小鱼，也可能吸走你的鱼漂！', 4, 5633);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (142, '星光蝠鲼', '宽大双翼流转璀璨星光，夜空下的梦幻之鱼，受惊瞬间遁入黑暗。', 4, 5600);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (140, '深渊吞噬者', '大嘴吸力恐怖，鱼钩常被吞没，拉上来时黏液拖一地，恶心又费劲。', 4, 5567);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (139, '死灵鲨鱼', '钓上来时它其实已经死了。可它仍在咬钩、仍在挣扎、仍睁着那只白眼看你。', 4, 5533);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (99, '狮子鱼', '外表华丽但棘刺有剧毒，属于可恶的，杀不尽的，还会在趁你不注意时挣扎着刺你一下的入侵物种。', 4, 5500);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (89, '锦鲤', '象征吉祥。但其实这种鱼也没那么稀有，所以卖不到什么价。', 4, 5467);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (88, '旗鱼', '背鳍高大如旗，速度极快。跟剑鱼打了很久的官司也没个结果。', 4, 5433);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (87, '大比目鱼', '大型的比目鱼，价值较高。比目鱼之大，一盘装不下。', 4, 5400);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (83, '光颌鱼', '能发出和感知红光的深海鱼。在黑暗的深海里，红光就是它的秘密武器，也是为什么会被你骗上岸的原因。', 4, 5367);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (80, '皇带鱼', '世界上最长的硬骨鱼，传说中的"海蛇"。当然，真正的海蛇另有其鱼。', 4, 5333);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (78, '腔棘鱼', '被称为活化石的古老鱼类。从恐龙时代游到现在的老古董，还没领完养老金就被你逮住了。', 4, 5300);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (73, '鲸鱼', '巨大的海洋哺乳动物，出水时喷出了漂亮的彩虹。', 4, 5267);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (71, '剑鱼', '上颌延长呈剑状。海洋中的剑客，用剑的方式却是靠打击……', 4, 5233);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (70, '蓝鳍金枪鱼', '金枪鱼中的极品，一口千金。呃，但好像你卖出去的时候它没那么贵。', 4, 5200);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (672, '蜃海方舟龟', '背壳残留一艘小型方舟的木板碎片，传说它是从那艘船上跳下来的。', 4, 5167);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (671, '浮雕鳞鱼', '背负着沉沦古城浮雕的一小块，搜集它兴许能拼起来能拼出半座城。', 4, 5133);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (670, '沙下潜行虎', '在沙下潜行的速度跟海里的鲨鱼一样快，看不见但能听见。', 4, 5100);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (669, '焚书祭祀鱼', '它出现的水面会漂起几张烧焦的古卷残页，作者无人考。', 4, 5067);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (668, '吞天小兽鱼', '体型不大，但它一张口能把头顶半亩天的色彩吸进去，吐出的是沙尘。', 4, 5033);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (667, '黄沙长刀鱼', '吻部是一柄黄沙凝的长刀，砍人没事，砍沙子立刻碎。', 4, 5000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (666, '千年井鲶', '一口干了千年的古井深处摸上来的鱼，胡须比身体长十倍。', 4, 4967);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (665, '复诵沙鬼鲈', '钓上来时鳃会反复复诵你最后那句话，反复直到死。', 4, 4933);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (664, '古祠香鳉', '总围着沉海的古祠香炉游，被钓起时鳃缝里冒出一缕余香。', 4, 4900);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (663, '沙漠之眼鳐', '体盘正中有一只巨大的闭着的眼睛，从不睁开，但它能看见你。', 4, 4867);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (662, '风干鳗', '体表像被反复风干过，但内里仍是活的，吃起来还带嚼劲。', 4, 4833);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (661, '法老葬鲷', '鳞片排列得像法老金面具的花纹，没人知道它从哪条河漂来。', 4, 4800);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (660, '旱魃残影鱼', '据说是远古旱魃留下的一缕残影所化，所到之处水一寸寸蒸干。', 4, 4767);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (659, '骸骨沙鲨', '整副脊骨外露，皮肉只剩极薄一层，但活得好好的。', 4, 4733);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (582, '寄潮鲶', '它跟着污染最重的潮一起来，潮一退它就走，它从来不属于任何固定的水域，只属于“潮”。', 4, 4700);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (581, '黯潮鳉', '在污染最严重的潮汐线生活，它的鳞色是潮水退后留下的那种深褐，一种你看见就会皱眉的颜色。', 4, 4667);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (580, '月毒鳗', '在被某种特殊月相照过的污水里养大，身上有一种淡淡的不属于这个时代的怪光。', 4, 4633);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (579, '浪渍鲈', '每次涨潮都会带回一身从陆地上冲下来的污垢，像一面会游的潮汐告示牌。', 4, 4600);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (578, '收尘清道鳉', '它的体表覆盖着一层从深渊各处吸附而来的奇怪粉尘，这些粉尘的来源每一粒都不同，但合在一起意外地与它的鳞色融合。', 4, 4567);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (577, '渣食鲷', '它的胃里是一团会发光的、混合了无数深渊废物的奇异胶质，据说能解某些罕见的诅咒。', 4, 4533);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (576, '食腐鳃鲈', '专吃深渊里那些已经腐烂但又奇怪地无法彻底死透的东西，它的鳃终年沾着一些不该沾上的色素。', 4, 4500);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (575, '净渊小鳗', '它是深渊清扫工的一种。它经过的水域，所有让人不安的“违和感”都会被它吞掉，留下的是稍微安宁一点的水。', 4, 4467);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (574, '渊渣鲶', '它在深渊底专门吞食那些“不该存在却又存在了”的残渣。研究者说，如果没有它，深渊早就被自己积累的怪东西塞满了。', 4, 4433);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (573, '沉碑虾', '一只小虾一直栖在某块古碑底下，而它的钳子上长着的一道纹理，正是那块碑上某个字的笔画。', 4, 4400);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (572, '凝望鳗', '它的目光永远朝着同一个方向，那个方向有一块远在数百海里之外的、还未被发现的古碑。它一辈子游不过去，但它一辈子都看着那个方向。', 4, 4367);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (571, '解碑鳃鲶', '据说它的鳃片纹路与某座海底古碑上的字一一对应，是一本会游的活拓片。研究者把它的鳃印拓下来，得到了一段没人能翻译的文字。', 4, 4333);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (570, '守碑鲦', '它一生都在某块海底古碑前后游来游去，从不离开太远。它似乎在守护那块碑，但它自己也不知道在守什么，只是它的祖先告诉它要守。', 4, 4300);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (569, '心外鲷', '心脏长在体表外侧，你能清晰地看见那枚比拳头小的紫红色器官在缓慢地搏动，它已经习惯了被这样看。', 4, 4267);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (568, '反生鲈', '它的鳞是反着长的，内脏可见。但你看着看着会发现，它的“内脏”位置完全跟你预想的相反，像是有人重新设计了一次。', 4, 4233);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (567, '外露鳃鲶', '鳃片长在体侧的两束肉柱上，像两束粉红色的羽毛挂在外面。每呼吸一次，羽毛就轻轻颤抖。', 4, 4200);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (566, '翻胃鳗', '它捕食时会把胃从口中翻出来包裹猎物，然后一边消化一边把胃缩回去。被钓起的瞬间，它没来得及把胃塞回去，你看见的是一条带着外置胃囊的奇怪生物。', 4, 4167);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (484, '白虎纹鲶', '体侧花纹像极了白虎的斑纹，但它的胆子比白虎小了不知多少倍。', 4, 4133);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (483, '朱雀血鲦', '少数血脉中带朱雀余烬的小鱼，激动时鳞片会泛起一点不属于水中的暖红。', 4, 4100);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (304, '坍缩鱼', '这种鱼会在海沙里造出小型空洞，一旦有什么在上面卧沙就会瞬间坍缩，只能被它捕食。', 4, 4067);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (302, '炽风鹏鸟鱼', '翼展五米掠沙飞行，俯冲时掀起焚风，老练的钓鱼佬的钓船会涂防火涂层。', 4, 4033);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (299, '法老鱼', '它的金鳞里卡着的细小石头有如镶着宝石，让捕食者对它敬而远之。', 4, 4000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (297, '烈日海龙蜥', '它利用背棘聚光，以让水中吐息温度超过100°C。', 4, 3967);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (296, '砂时虫', '钻行时似乎会扰动时间流，但仅限让周围沙粒悬浮的程度。', 4, 3933);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (264, '月虹鳟', '会随月相变换银紫双色，据说只在月蚀夜现身，但此刻被你钓到了。', 4, 3900);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (263, '妖精龙幼鱼', '有着蝶翼状的腮与软体生物的触角，还眨着那对看似人畜无害的眼试图蒙骗你……千万别被骗了。', 4, 3867);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (242, '岩髓萃取者', '长舌钻入裂缝吸食半熔岩髓，钓起时滴落炽热“岩浆蜜糖”。', 4, 3833);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (241, '硫磺公爵蟹', '巨螯熔炼硫磺铸成“黄金”铠甲，华丽…但臭味弥漫三条街。', 4, 3800);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (239, '地核脉冲鳐', '腹部感应地心震动，释放冲击波震晕猎物，钓手可能一起晕船。', 4, 3767);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (236, '黑烟领主鱼', '统帅热泉生态圈，吞吐毒云如活烟囱，没有防毒面具的话要小心。', 4, 3733);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (234, '地幔蠕虫', '钻透岩层吞噬熔岩，钓起时喷发灼流，鱼竿耐久度好像在狂掉……', 4, 3700);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (233, '熔岩鲸虱', '寄生在岩浆房巨兽体表，甲壳红热如烙铁，用镊子夹取时滋滋响。', 4, 3667);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (192, '全息领主鱼', '操控逼真全息投影分身群，哪个是真身？赌一把吧！', 4, 3633);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (191, '能量虹吸怪', '吸收光、热、声波转化能量，钓竿电池被吸干是常事。', 4, 3600);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (189, '量子纠缠对鱼', '一次钓起两条！伤害其一，另一条会同步受伤哀嚎…有点瘆人。', 4, 3567);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (187, '行星钻探虫', '头部合金钻头轰鸣，钓起后还在试图钻穿你的钓桶。', 4, 3533);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (186, '纳米风暴鱼', '释放纳米云修复环境或分解污染物，失控时连鱼竿都会整个分解掉。', 4, 3500);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (184, '反物质水母', '腔体内禁锢微量反物质，泄露的话将是微型烟花…或大爆炸。', 4, 3467);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (141, '混沌章鱼', '会看心情拟态的神秘章鱼，钓起前是啥？鱼？水母？海草团？每次开盲盒都充满“惊喜”。', 4, 3433);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (138, '风暴鲸鱼', '钓它那天空一定会下雨。钓上来后那场雨突然停，仿佛本来就是好天气。', 4, 3400);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (137, '冰霜巨口鱼', '张开嘴的瞬间附近水会结一层冰皮，它咬饵的时候鱼线常被冻在水里。', 4, 3367);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (136, '地狱火鲈鱼', '它的体温能把鱼篓的木头烤出焦痕。老钓鱼人会专门带一只铁桶来关它。', 4, 3333);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (135, '九头蛇鱼', '九个小脑袋共用一具身体。咬钩时只有一个头被骗到，剩下八个仍在四处张望。', 4, 3300);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (134, '海龙幼崽', '巴掌大的小龙已经会喷一掌宽的水柱，最远的一次把岸上钓鱼人的帽子打飞了。', 4, 3267);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (86, '鳕鲈', '生活在海底峡谷边缘的鱼类。悬崖边的居民，随时准备跳崖。', 4, 3233);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (84, '角鮟鱇', '雌雄体型差异巨大的深海鮟鱇，由于深海同族难以偶遇，运气好的雄性会寄生在雌性身上，至于运气不好的嘛……', 4, 3200);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (82, '水滴鱼', '离开深海高压环境后变成一滩凝胶状，跟小美人鱼下海会变成泡沫相反，忧郁的王子殿下上岸就会“融化”。', 4, 3167);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (81, '尖牙鱼', '牙齿相对于体型来说非常巨大，满嘴尖牙却只有巴掌大，是深海鱼怪的雏形。', 4, 3133);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (79, '桔连鳍鲑', '寿命极长，生长缓慢的深海鱼。时间对它来说只是数字，是不是羡慕了？', 4, 3100);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (77, '沉没的宝箱', '装着一些可有可无的旧物。打开它，也许有惊喜，也许是破烂。', 4, 3067);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (76, '深海鮟鱇', '用头顶的"灯笼"诱捕猎物。自带探照灯的深海猎手。', 4, 3033);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (75, '海龟', '长寿的海洋爬行动物。慢悠悠的生活，能活上百年。', 4, 3000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (74, '电鳗', '能释放强大的电流。新手钓起来会被吓得扔掉钓竿，应该是被吓的吧？', 4, 2967);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (72, '海豚', '聪明友善的海洋哺乳动物。它们总是面带微笑，但也可能正在通过海豚加密通道悄悄骂你。', 4, 2933);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (69, '娃娃鱼', '学名大鲵，叫声似婴儿啼哭。晚上钓起来也怪吓人的。', 4, 2900);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (68, '清道夫', '常被误认为能清洁水质。其实它只会制造垃圾，还很难杀，最可恶的是明明恨得让人牙痒，却没什么肉可吃。', 4, 2867);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (67, '金龙鱼', '价值不菲的观赏鱼。水族箱里的贵族，贵还是指价格。', 4, 2833);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (482, '玄龟脉鲷', '身体微微带着玄龟一族的厚重感，鳞下能看见似龟纹的黑色暗纹。', 4, 2800);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (481, '麒麟血鲈', '据说远祖是某只山中麒麟，血脉淡了千代，只剩下一对眼睛仍带着古兽的气场。', 4, 2767);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (480, '撼雷虾', '个头不大但敢顶着雷云出水，是雷雨海里少有的胆大鬼。', 4, 2733);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (479, '雷蕴鲷', '鳞片下隐隐流着一道金光雷纹，被它打过的鱼饵会带着一缕电味。', 4, 2700);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (478, '引雷小鳉', '体内有一缕被引来的天雷余意，钓起时手会被狠狠地酥麻一下。', 4, 2667);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (477, '雷感鲈', '暴雨欲来时它会浮上水面静默不动，像在等什么，这是它独有的“渡劫预演”。', 4, 2633);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (476, '沉钟鳔鱼', '古潭底沉了一口大钟，它的鳔房就在钟里筑成，每动一动钟壁就咣的一声。', 4, 2600);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (475, '啮怨鳗', '这种鳗鱼专门啃食古潭底沉积的怨气，也因此长得越来越带着一种说不清的怨意。', 4, 2567);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (474, '阴怨鲈', '终年生活在阴气重的古潭中，被钓起时四周的水温会骤降几度。', 4, 2533);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (473, '古潭血鲶', '据说曾发生过几桩凶事的古潭里游出来的，体表的血纹至今洗不掉。', 4, 2500);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (472, '香火鲷', '长年游在断了香火的仙门池中，自身也染上了一抹萎靡的灰香，但它还在固执地等着新的香火。', 4, 2467);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (471, '钟鸣鳉', '每到日落，体内会发出像极微弱钟声的共鸣，这是它从仙门旧钟那里学来的余音，可惜钟早碎了。', 4, 2433);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (470, '寒池幽鲤', '仙门遗下的寒池里养出的，皮下血是淡蓝色的，触手刺骨，但据说炖汤最能补阳气。', 4, 2400);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (469, '守池老鲶', '仙门的弟子都散尽了，只剩它在池底独自守着，胡须长到能绕池一圈。它是这片寂静的最后管家。', 4, 2367);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (468, '仙门遗鳞', '在某座废弃仙门后的池子里游了不知多少年，鳞片上还印着褪色的山门徽记，但徽记是哪一门它早就忘了，钓鱼人也认不出来。', 4, 2333);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (390, '同步轨道鲨', '总是按一个固定的圆周路径巡游，路径精确得像被刻在某条早就消失的轨道上。', 4, 2300);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (389, '微重力鲷', '身体里没有完全适应重力，水中游动姿势像在跳慢动作的舞，离水时却会突然瘫软。', 4, 2267);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (388, '真空适应鳗', '据说原本生活在轨道空间站外壳上，掉到海里以后还在以轨道速度绕着自己转圈。', 4, 2233);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (387, '倒挂鲈', '习惯性头朝下游动，因为它身体里有一截器官的重力方向是反的，矫正过几次都没成功。', 4, 2200);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (386, '浮升腔河豚', '它体内有一颗稳定的反重力腔，鼓起来的时候它会实打实地飘起来，与生气无关。', 4, 2167);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (385, '溶氧调节鲷', '它呼吸时会排出富氧气泡，是某个殖民工程的环境监理员，至今仍尽职地工作着。', 4, 2133);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (384, '温控鳃鲸', '这条不大的小鲸能让方圆十米的水温稳定在它喜欢的恒温值，因此身边总聚着一群凑暖的小鱼。', 4, 2100);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (383, '改造观察兵鱼', '眼睛里嵌着多频段镜头，仍在按惯性扫描周围目标，但接收端早已不存在。', 4, 2067);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (382, '隐形特攻鳗', '表皮启动时会折射出环境光彩，你看见水波微微起伏才知道它来过；这具身体原本挂在某支特种部队的编制表上，现在它自己游了。', 4, 2033);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (381, '装甲突击鲨', '一身军用合金贴片，残留着不知道哪次战役的烧灼痕，至今见到铁血味的渔船就跟。', 4, 2000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (262, '远古黑鳞清道夫', '生时对其他鱼类有害，死时污染环境，你只能花钱合法处理掉的麻烦鱼类。', 4, -2000);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (294, '流金蚁狮鱼', '这种鱼会在沙底筑好漏斗陷阱，给掉入其中的猎物注入消化金砂的黏液，钓钩也常常被这样溶蚀。', 3, 750);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (292, '帝王蝎狮鱼', '前半身蝎甲，后半身鱼尾，毒钩与尾鳍并用，水陆双栖的噩梦。', 3, 746);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (290, '沙漠雷霆鲀', '摩擦鳞片迸发电火花，随时准备引发小型雷尘暴！老练的钓鱼佬会备好避雷针。', 3, 742);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (289, '陨星吸食者', '磁化的口器会在捕食时顺便吸附铁陨碎片，让它的胃囊里沉积了星辰砂，可惜有点恶心。', 3, 738);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (231, '淬毒热泉蛇', '毒牙混合硫化物与热毒，被咬伤口溃烂且散发煮鸡蛋味。', 3, 734);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (230, '震波预警鱼', '感知地壳震动狂抖，提前30秒预警喷发…准确率？看它心情。', 3, 730);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (227, '合金沉积鲷', '体内富集热液金属，鳞片闪烁青铜光泽，鱼骨是上等焊料。', 3, 726);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (225, '火山炸弹河豚', '遇险吸入熔岩碎片膨胀，喷发时甩出炽热渣球，就连船的甲板都会因此留坑。', 3, 722);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (224, '地裂招潮蟹', '巨螯敲击裂缝诱发微型喷发，驱赶天敌，也可能掀翻钓船。', 3, 718);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (180, '神经接口乌贼', '触须链接触发幻觉：看见宝藏或自己变成鱼。持续5分钟。', 3, 714);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (178, '跃迁鲑鱼', '短距离瞬移闪现！咬钩后可能突然出现在你背后的桶里。', 3, 710);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (177, '生态改造蟹', '钳子会喷射基因喷雾，让周围藻类变荧光粉或长腿乱跑…', 3, 706);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (176, '重力锚章鱼', '吸盘会开启局部重力场，拉它像拽铅球，关掉后轻如纸片。', 3, 702);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (175, '克隆水母', '受刺激分裂成两个，但复制体常缺触手或脑子（如果有）。', 3, 698);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (133, '时间扭曲鲑鱼', '它身边的水流得最慢。你把鱼钩放进去，鱼钩沉下去也会比别处慢半拍。', 3, 694);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (131, '巨人鲟鱼', '把它拉出水要三个壮汉合力，不过不讲武德的捕鱼人一般也不仅仅有钓鱼竿。', 3, 690);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (130, '凤凰鲤鱼', '焚烧后灰烬里会孵出新的鱼苗，每次复生都比上次小一号，再过几代它就消失了。', 3, 686);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (129, '塞壬鲛鱼', '歌声只对水手起效，钓鱼人听了什么也没有。但它分不清水手和钓者，仍唱得卖力。', 3, 682);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (66, '蝰鱼', '牙齿极长，无法完全闭合嘴巴。看着非常唬人，是深海里的吸血鬼。', 3, 678);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (62, '军曹鱼', '体型像鲨鱼，常跟随大型海洋生物。鲨鱼的跟班，狐假虎威。', 3, 674);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (61, '鲯鳅', '体色鲜艳，游泳速度快。海里的一抹亮色，捕捞时颜色会变。', 3, 670);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (59, '匙吻鲟', '吻部像船桨，滤食性。自带“船桨”的远古生物。', 3, 666);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (58, '鲟鱼', '古老的鱼类，产鱼子酱，或者说产黑色黄金。', 3, 662);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (51, '鲷鱼', '体色鲜艳，寓意吉祥。过年过节常备，喜庆。', 3, 658);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (50, '石斑鱼', '名贵的海产鱼类，是藏在礁石中的美味。难怪要藏。', 3, 654);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (49, '金枪鱼', '高速游泳的大型鱼类。寿司店里的贵族，贵是指价格。', 3, 650);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (658, '旧碑沉鱼', '总绕着一块半埋的旧碑游，碑上的字早被沙磨掉，但它还认得。', 3, 646);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (657, '砌塔沙蟹', '会用细沙在沙底砌迷你金字塔，金字塔在它死后会立刻塌掉。', 3, 642);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (656, '银砂蛇鳗', '钻进沙里时尾巴会溅起一波银亮的细砂，远看像撒了把钱币。', 3, 638);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (655, '焦烟脊鱼', '背脊冒的不是水汽是焦烟，离水十秒鳞下的肉就开始焦化。', 3, 634);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (654, '失语女祭鳉', '据说是某神庙最后一位女祭司被沙埋时化的，从此再也不出声。', 3, 630);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (653, '回旋沙蟹', '螯只有顺时针拧才能掰开，逆时针任你大力金刚也没用。', 3, 626);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (652, '红铜雕鲶', '体表纹路像被刻刀錾过的红铜，是某个已消失文明留下的符号。', 3, 622);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (651, '砂晶折光鳐', '翅展开始折射阳光，让追它的天敌短暂失明。', 3, 618);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (650, '古坟守门鳉', '古坟入口水洼里游了百年的小鱼，传说赶不走它就别想进坟。', 3, 614);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (649, '祈雨鲷', '它跃出水面那一刻，远方的沙暴就会停下，但只停几分钟。', 3, 610);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (648, '渴血沙蝎鱼', '尾刺真的能扎人，扎完伤口会渗出微量沙粒，这就是它的血。', 3, 606);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (647, '石棺寄居鳗', '总钻进废弃的法老石棺里筑窝，钓起时石棺也跟着上来一截。', 3, 602);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (646, '黑曜鳃鲈', '鳃片像被火山熔岩淬过，敲上去会迸出微弱的火星。', 3, 598);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (565, '梦渣鲷', '它会从口中吐出一些细小的、半透明的渣滓，据说那是从睡眠者身上掉下来又被它捡起的“梦的废料”，收集十枚可以在某种黑市交易“清醒”。', 3, 594);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (564, '半梦半魇鲦', '它的左半身是温和的银色，右半身是带着说不清痛感的深红色，一半善梦一半魇，而它把哪一半给你，看心情。', 3, 590);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (563, '噬眠鳉', '接触过它的鱼具会让人当夜失眠，直到把鱼具丢了为止。', 3, 586);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (562, '倒影鲈', '它在水中没有倒影，而你看它时，你的倒影里多了一条它。', 3, 582);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (561, '噩梦小鲶', '触它的人当晚必做噩梦，但梦内容醒来就忘。它似乎只是路过，顺手把人的好梦换走。', 3, 578);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (560, '沉钟鳗', '它发出的声音是水底深处一口已经无人记得的钟的余音，你不会真的“听见”，但你的胸口会闷一下。', 3, 574);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (559, '三响鲷', '它的尾鳍每次摆动是三下一组，精确得像数过，而井底鱼的尾鳍据说都是这样。', 3, 570);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (558, '古井苔鲶', '它的胡须上挂着一种只在特定古井底下才长的青苔，而那种古井早就被填了。', 3, 566);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (557, '回声鲈', '你对它说话，它的鳃会以两秒后的延迟，微微地颤动一下，精确得像是在回应。', 3, 562);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (556, '井底鳉', '它从一口很深很深的古井里游出来，身体仍带着井水那种暗哑的安静。', 3, 558);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (555, '边缘感染鲷', '它身上没有任何明显的异变，但你拿尺子量它，会发现每一处尺寸都和“正常的鲷鱼”差出几分之一，差的方向都是同一个。', 3, 554);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (554, '余触小鲦', '它体侧有一道细细的擦痕，像是被某种触手非常温柔地划过一次留下来的；而温柔本身就是它最让人不安的地方。', 3, 550);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (553, '染斑鳗', '它身上有一片像是被某种巨大之物的影子轻轻盖过一次留下的浅色斑痕，从此那片皮肤再也不长鳞了。', 3, 546);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (552, '神残鳃鲷', '它的鳃片背面长着一些极其细小的、形状像是某种更高存在的指纹一样的纹路。', 3, 542);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (551, '鳞屑感染小鲈', '它鳞缝里有一种淡蓝色的、不知道是不是某位古神蜕下的、像是粉末一样的东西。研究者建议：不要碰它的鳞缝。', 3, 538);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (550, '伪鲶', '它和这片海里所有正常的鲶鱼看起来一模一样，但它出现的瞬间，这片海里其他所有鲶鱼会同时停下不动几秒钟，然后假装什么都没发生。', 3, 534);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (549, '端正鳉', '它的左右两侧极其严格地对称，严格得像被尺子量过的，你能看出每一片鳞的位置都不允许有任何偏差，这种端正正是它最不对劲的地方。', 3, 530);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (548, '几乎完美鲦', '完美得过头了，以至于你看它时，它身边其他正常的鱼相形之下都显得不太对劲。', 3, 526);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (547, '像极了普通鲷', '它真的非常像一条普通的鲷鱼，你一切都说不出来，但你的手就是不愿意去碰它。', 3, 522);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (546, '看似正常鲈', '你看它一眼是普通的鲈鱼，看第二眼会觉得肚腹的弧度有那么一点不对，看第三眼你就不想再看了。', 3, 518);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (467, '莲根鲷', '总缠在莲根之间，偶尔会被当成莲根挖起来。', 3, 514);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (466, '共鳞菌鳉', '鳞缝里寄生着一种奇异的灵菌，互相养着也算般配。', 3, 510);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (465, '灵草小鲢', '头顶常常顶着一段从灵草里长出的绿芽，是它和灵草的默契。', 3, 506);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (464, '鸣剑鲈', '鳞片在剑气流过时会发出微弱的金属共鸣，像一把不愿出鞘的剑。', 3, 502);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (295, '蜃楼鲸', '喷水柱折射成巨型鲸鱼的幻影，靠近了看会发现它的实体是条30厘米小鱼。', 3, 498);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (293, '砂岩歌姬鱼', '振动鳔囊发出遗迹歌谣，听者恍惚见幻影古城，曲终人怅惘。', 3, 494);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (291, '石化凝视鱼', '双眼射出麻痹射线来捕食，但有时僵直的也包括它自己。', 3, 490);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (288, '木乃伊鲶', '体表缠绕防腐藻带，所以离水也能存活三日。', 3, 486);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (287, '黑曜石刃鱼', '鳍边缘锐利如玻璃，切割渔网对它来说轻而易举，记得带上合金箱当鱼篓。', 3, 482);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (286, '太阳祭坛鳐', '背纹如古日晷，据说正午时投射的阴影会指向藏宝点。', 3, 478);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (232, '水晶洞鲶', '胃囊分泌矿物溶液，呕吐筑巢成微型水晶洞，撬开取晶需快准狠。', 3, 474);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (229, '沸海骑士虾', '骑乘沸腾气泡流冲锋，长矛是硬化硫磺柱，冲锋结束矛也化了。', 3, 470);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (228, '熔心寄生虫', '钻入岩缝吸食地热，钓起时带出灼热岩核，拿稳了！锅垫！', 3, 466);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (226, '黑烟之魂水母', '半透明躯体包裹毒烟，触须飘散如活体烟柱，不小心吸入会咳嗽半小时。', 3, 462);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (223, '岩浆泳者鱼', '会短暂冲入熔岩层捕食，体表冷却岩壳剥落的时候就像在蜕皮，烫伤警告。', 3, 458);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (182, '全息诱饵鲸', '投影巨型鲸影吓跑小鱼，可惜像素低，看着像马赛克积木。', 3, 454);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (181, '酸液喷射鱼', '口腔加压喷射腐蚀液，能溶穿铁皮，鱼饵桶要小心！', 3, 450);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (179, '能量护盾河豚', '膨胀时展开EMT能量罩，硬如合金！敲起来铛铛响，但耗能快，马上就会泄气。', 3, 446);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (174, 'EMP电鳐', '释放电磁脉冲，让附近电子设备短暂失灵，包括你的智能鱼竿。', 3, 442);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (173, '激光切割鱼', '眼部发射弱激光切水草，走火时可能烧穿渔网！', 3, 438);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (132, '巫师帽鱼', '背鳍真是一顶巫师帽形状。传说戴上能多记住一个咒语，但只能记住一晚。', 3, 434);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (128, '元素融合鱼', '左半身永远冒蒸汽，右半身永远结薄霜。要从中间剖开下锅，否则这锅永远别想熟了。', 3, 430);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (127, '石像鬼石斑鱼', '白天蜷在石堆里像块普通石头，日落后它会缓缓睁眼，谁跟它对视谁就被咬。', 3, 426);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (126, '梦境鲱鱼', '煎过的鱼肉吃下去当晚必做梦，梦的内容是它本来要做的那个梦。', 3, 422);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (125, '毒液狮子鱼', '毒腺里的毒能让人三天三夜没胃口。魔女炼药也只会取极少量，多一滴会出事。', 3, 418);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (124, '雷霆鳗鱼', '钓起的瞬间整根钓竿都在发麻，电流从手腕一路窜到肩膀，那是它最后的「惊吓」。', 3, 414);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (65, '灯笼鱼', '深海中最常见的发光鱼类，黑暗中的小灯笼，虽然只有一点点，但也算是照亮了深海。', 3, 410);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (64, '鮟鱇鱼', '长相奇特，用诱饵捕食。深海中的钓鱼高手，头顶自带鱼竿，如今输给了你。', 3, 406);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (63, '梭鱼', '体型细长，牙齿锋利的海中猎手。速度极快的海中刺客，也没有自己的信条。', 3, 402);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (60, '鲶鱼', '有胡须，种类繁多，从大到小。在被清炖之前坚称龙的胡须取自于它。', 3, 398);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (57, '鲑鱼', '会洄游产卵的著名鱼类。是逆流而上的勇士，然后被熊一巴掌拍晕。', 3, 394);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (56, '鳟鱼', '生活在清澈冷水中，种类繁多。水质好的标志，飞蝇钓的目标。', 3, 390);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (55, '大口黑鲈', '北美最受欢迎的游钓鱼之一。路亚爱好者的梦中情鱼。', 3, 386);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (54, '狗鱼', '体型细长，嘴巴像鸭嘴。不会汪汪叫，真是一场骗局。', 3, 382);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (53, '章鱼', '非常聪明，有很多触手。海底的智多星，会开瓶盖哦。', 3, 378);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (52, '食人鱼', '牙齿锋利，成群时很危险。亚马逊的恐怖传说，但单独一条并不可怕。', 3, 374);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (48, '鲨鱼', '海洋中的顶级掠食者之一。别怕，不是所有鲨鱼都吃人。', 3, 370);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (47, '胭脂鱼', '色彩艳丽的保护动物，这么美，还是让它留在水里吧，只是它咬钩的时候不这么想。', 3, 366);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (46, '鳜鱼', '又称桂鱼，名贵食用鱼。桃花流水鳜鱼肥，文人墨客也爱它。', 3, 362);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (45, '黑鱼', '生性凶猛的掠食者。池塘里的恶霸，能制裁它的只有你了！', 3, 358);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (44, '鲈鱼', '肉质鲜美，适合清蒸。清蒸是对它最大的尊重。', 3, 354);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (463, '怯刃鳉', '听说在剑冢附近的水域避之不及，是修仙界胆子最小的鱼。', 3, 350);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (462, '剑感鲦', '能感受到水中残留的剑气，钓它最好用普通鱼竿，剑客的鱼竿一靠近它就跑。', 3, 346);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (461, '半化半藏鱼', '一半像鱼一半像孩子，化形修了一半就停下了，停得有点尴尬。', 3, 342);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (460, '学礼鳉', '见到钓鱼者会鞠一个不太标准的躬，鞠完才意识到自己是条鱼。', 3, 338);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (459, '半语鲶', '能说出一两个似是而非的字，但对话永远只能完成一半。', 3, 334);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (458, '半人面鲈', '偶尔会摆出像在思考的眼神，但其实它只是被惊得发愣。', 3, 330);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (457, '余焰鲦', '体内残留一丝丹火，冬天靠它取暖的修仙小辈不在少数。', 3, 326);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (456, '余韵鲷', '被炉火淬炼过的肉，蒸出来连水都是药汤味。', 3, 322);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (455, '废炉鳔虾', '在废炉灰里啃食长大的，钳上的纹路是炉火烧出来的。', 3, 318);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (454, '化药鳃鲀', '鳃里长出了药材般的细丝，钓上来时会顺着伤口冒出几缕药气。', 3, 314);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (453, '残丹鳗', '误吞过整粒废丹的鱼，腹中还含着一团没化尽的丹渣，敲一敲会响。', 3, 310);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (452, '千载小鲫', '不大的鱼，但鳞片纹理一圈一圈像年轮，据说一圈是百年。', 3, 306);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (451, '隐池鲈', '钓上来才发现池水被它带出来一汪，它的真身是它脚下那块隐界。', 3, 302);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (450, '福地灵鳉', '福地之水里游出来的，身体周围常年浮着一圈极淡的灵晕。', 3, 298);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (449, '仙居小鲦', '据说是哪位散仙忘了带走的池鱼，一直等着主人回来。', 3, 294);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (448, '洞天净鳞', '在某座洞天的内池里养了百年，鳞片洁净得像没被时间碰过。', 3, 290);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (380, '嗅毒鳉', '其实是改造过的水质监测员，遇到污染就会皱起整张脸。', 3, 286);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (379, '警报鳗', '一感受到水中异常物质，皮肤就闪烁红光，是水域里的活体烟雾报警器。', 3, 282);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (378, '转基因青苔鱼', '半鱼半藻的混合体，被钓起后还会继续光合作用，活得有点理直气壮。', 3, 278);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (377, '编号污染鲶', '据说是基因调试时的边角料，带着一身原本不该出现的荧光斑点。', 3, 274);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (376, '双色镜面鳉', '大概是某次水域净化的副产物，体表分两种鳞，一半倒影一半正像。', 3, 270);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (375, '抖位虾', '紧张时会瞬间挪到视线右侧30厘米处，像帧率掉了的录像。', 3, 266);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (374, '闪移鲑', '在视野里“啪”地消失再“啪”地出现，距离短得令人怀疑是不是自己花眼。', 3, 262);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (373, '装甲蛛鳐', '八片胸鳍各自带着一小段甲胄，伸开像把生物伞，撑开后游速反而更快。', 3, 258);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (372, '钢颚鲈', '颌骨上嵌着合金齿列，咬钩时金属相撞声特别清脆。', 3, 254);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (371, '节肢鳃鲀', '体表关节处有外露的几节装甲，遇到威胁会咔哒一声合拢成球。', 3, 250);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (285, '水晶根须鱼', '头部寄生地下水晶矿脉，游动时拖拽微光晶丝，但偶尔会缠住水草。', 2, 75);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (284, '沙暴鳗', '当这种鳗鱼开始卧沙时意味着海中的沙暴即将到来，准确率比海气预报要高。', 2, 75);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (283, '热浪幽灵虾', '高温下身形会扭曲如透明涟漪，明明在夜中会凝结为实体，捏一捏却只有满手沙。', 2, 74);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (280, '旅人蕉鳗', '拟态枯萎蕉叶漂浮，受伤时会分泌清甜汁液并弃叶逃跑，就像壁虎断尾一样逃生。很多捕食者追它只是为了它那清甜的弃叶，并非真要吃。', 2, 74);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (279, '毒蝎斗鱼', '这种鱼的尾刺会注射神经毒素，能使猎物精神抖擞数10分钟，然后因劳累而暴毙。', 2, 73);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (222, '淬火剑鱼', '吻部能急速冷却形成玻璃质尖刺，华丽但易碎。', 2, 73);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (220, '矿物探测器蟹', '钳感应矿物共振，但总把你的鱼钩当铁矿哔哔乱响。', 2, 73);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (218, '熔岩滤食蚌', '壳缝滤食热液金属粒子，体内沉淀微量金砂，不过这种程度只能做粒鼻屎大的金珠。', 2, 72);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (217, '蒸汽推进鱼', '吸水喷出高温蒸汽冲刺！方向随机，常常撞到海底烟囱眼冒金星。', 2, 72);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (171, '脉冲通信金枪', '发送短脉冲信号，内容只有：“饿…吃…”', 2, 71);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (169, '悬浮灯笼鱼', '内置反重力核心，提起来轻飘飘，发光却像接触不良的灯泡。', 2, 71);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (168, '翻译海螺', '声称翻译鱼语，输出全是乱码或哲学冷笑话。', 2, 71);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (166, '维修机器人鱼', '六只机械臂可拧小螺丝，但工具箱常忘带焊锡。', 2, 70);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (123, '暗影泥鳅', '它不是躲在阴影里，它就是阴影里多出来的那一截。要钓它先得盯住一片影子很久。', 2, 70);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (122, '圣水天使鱼', '鳞片碎屑泡水能洗去衣服上的旧污渍，但只洗五年以内的，再老的污它没办法。', 2, 69);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (120, '妖精金枪鱼', '速度快得能把水拉成一道细线，可惜每次都忘了自己刚才往哪个方向冲。', 2, 69);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (119, '幻影鳕鱼', '你看着它，它就在那；一眨眼，它就在你看不见的位置。', 2, 69);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (43, '鳞鲀', '有一个可以锁定的背鳍棘刺。小心它的“锁喉”绝技。', 2, 68);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (42, '斧头鱼', '身体侧扁像斧头，深海发光鱼，是自带光芒的深海“斧头”。', 2, 68);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (41, '鲭鱼', '体型纺锤，游泳速度快。海中的游泳健将，越游肉质越紧实。', 2, 68);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (36, '羊头鱼', '牙齿像羊齿，能咬碎贝壳。算是海里的“羊”，毕竟专吃硬壳。', 2, 67);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (34, '玻璃梭鲈', '眼睛在光下会反光，夜行性，好似暗夜中的幽灵，目光如炬。', 2, 67);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (27, '鲳鱼', '肉厚刺少。懒人吃鱼首选，放心大口吃。', 2, 66);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (26, '黄花鱼', '分为大黄鱼和小黄鱼。大小都是蒜瓣肉，鲜嫩无比。', 2, 66);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (25, '带鱼', '身体扁长如带。海里的银色飘带，也是餐桌常客。', 2, 66);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (645, '火舌鳞鲫', '鳞片在阳光下反出像火舌一样的红光，但摸起来是凉的。', 2, 65);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (24, '鲅鱼', '体型较长，常做熏鱼。熏制之后，风味更佳。', 2, 65);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (644, '隐沙蜥鱼', '整条鱼能贴在沙面上变成沙的颜色，不动起来绝对找不着。', 2, 64);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (643, '回声沙鳉', '一群同时被钓起，会齐声发出沙暴前夜里听过的低吼。', 2, 64);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (642, '干裂蟾鱼', '表皮永远像干涸沙地的裂纹，用沙粒一搓能搓出皮屑。', 2, 64);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (641, '风干银鳞', '风沙刮过的银鳞会脆得能掰断，但掰断后又会慢慢长回来。', 2, 63);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (640, '月栖虎鱼', '白天藏在沙下，月夜才浮上来，体色随月相微微变化。', 2, 63);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (639, '沙号角螺', '壳形像号角，吹起来真的能发出号角声，一吹就有沙落出。', 2, 62);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (638, '拟螯沙鲶', '背鳍形状像螃蟹螯，是跟沙蟹长期争食留下的拟态。', 2, 62);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (637, '倒立行走鳉', '不会游泳，靠尾鳍在沙面上倒立挪动，行进姿态滑稽。', 2, 62);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (636, '锈砂鳗', '在某条早已干涸的旧河床里挖出来的，体表带着一层铁锈。', 2, 61);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (635, '涸辙鱼', '沙漠车辙印里游出来的鱼。传说一离辙就死，但现实里能活半个月。', 2, 61);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (634, '沙琥珀虾', '体表凝着一层金黄沙琥珀，敲起来咔嚓响。', 2, 60);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (633, '磨齿沙鱼', '牙齿是被风沙磨平的，嚼东西像砂纸打磨。', 2, 60);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (632, '旱井鲤', '旱井里养出来的鲤鱼，鳞片偏褐，带着一股井水旧味。', 2, 60);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (631, '沙暴前哨蟹', '沙暴来前一天会爬上沙丘齐声叫，比观星盘还准。', 2, 59);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (545, '沉吟鲦', '它常年在水底吟着同一段无意义的音节，而那段音节会在你脑里盘几天才散。', 2, 59);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (544, '鳃语小鲶', '钓起来后它的鳃还在小声说着什么，你越听越不想听。', 2, 58);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (543, '复声鲷', '它发出的声音永远像两个人在同时低语，只是你只看到一条鱼。', 2, 58);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (542, '喃喃鳉', '即使在水里也能听见它在小声咕哝，从未停过。', 2, 58);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (541, '私语鲈', '鳃口发出的声音听着像低声耳语，凑近了听是听不懂的字。', 2, 57);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (540, '重生小鲦', '钓上来咬钩的不是它，是它身上长的另一张嘴。', 2, 57);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (539, '缠骨虾', '它的钳子里夹着另一只虾的一截外骨骼，夹了不知道多久。', 2, 56);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (538, '复体鳉', '同时寄生在三条鱼上，这三条鱼一起被你钓上来。', 2, 56);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (537, '残体鲶', '它的鳃边长着另一条小鱼的半截身体，那半截还会动。', 2, 56);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (536, '寄生小鳗', '一辈子都缠在大鱼身上，被钓起的时候发现它身上还吊着另一条。', 2, 55);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (535, '噗噗鲦', '它呼气会发出“噗噗”声，但它呼气的频率不是任何呼吸节奏。', 2, 55);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (534, '异哨小鲶', '钓起来时它的鳃发出的不是闷哼，是一种细细的口哨声。', 2, 55);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (533, '滴答鳉', '它静止时鳍还在以钟摆的节奏摆动，精确得让人毛骨悚然。', 2, 54);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (532, '错频鲷', '鳍颤的频率永远比身体快半拍，听久了会让人头疼。', 2, 54);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (531, '哑鸣鲈', '它的鳍每动一次就发出一声不属于水中的“嘀”，像金属敲玻璃。', 2, 53);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (530, '浊瞳鲦', '两眼浑浊一片，据说是看了不该看的东西落下的后遗症。', 2, 53);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (529, '干眼鲷', '它的眼睛是干的，在水里也是干的，你不要去研究为什么。', 2, 53);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (528, '蒙瞳小鳉', '眼皮永远盖着，从未睁开过，但它能“看见”你。', 2, 52);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (527, '双盲鲈', '两只眼睛都瞎了，但水里它比谁都游得稳。', 2, 52);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (526, '失瞳鲶', '一只眼睛是空的，空得能听见风穿过。', 2, 51);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (447, '焦丹鲷', '身上有几片烧焦的鳞，是从溢出的丹火里幸存下来的。', 2, 51);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (446, '炼厌鳔', '炼丹失败之水里养出的，对所有香味都本能地皱眉。', 2, 51);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (445, '残气小鲶', '吸了太多丹炉余烟，鳃里冒灰烟，像是个老烟枪。', 2, 50);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (282, '齿轮遗民鱼', '啃食废弃机械城油污为生，鳞片闪烁铜锈光泽，身上没有腥味，而是带着柴油味。', 2, 50);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (281, '赭石变色龙鱼', '随沙色变幻体色，但紧张时会固定成荧光粉，是隐身失败的典范。', 2, 49);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (278, '镜面鲷', '鳞片反射强光致盲天敌，老练的钓鱼佬会戴墨镜就是这个原因。', 2, 49);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (277, '月光泉天使鱼', '仅月夜现身绿泉，鳞粉洒落处萌发脆嫩草芽，日出即枯萎。', 2, 49);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (276, '流沙鲶鱼', '潜伏沙底张嘴制造漩涡，猎物陷入瞬间闭口吞沙……所以消化系统常年堵塞。', 2, 48);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (221, '隔热鳞鲶鱼', '层鳞片隔绝高温，摸起来像石棉瓦，环保性存疑。', 2, 48);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (219, '共生管虫鱼', '与嗜热菌共生，头顶鲜红菌丝如鸡冠，菌死了鱼也凉。', 2, 47);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (216, '酸液藤壶怪', '喷射弱酸溶解岩石钻孔，偶尔误伤钓线留下焦痕。', 2, 47);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (215, '地磁导航鳗', '感知地磁极在热液区找路，强喷发时导航乱码转圈圈。', 2, 47);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (214, '结晶护盾虾', '用凝固熔岩铸甲壳，防御力不错，但自重沉得游不动。', 2, 46);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (213, '热液喷口鱼', '会守株待兔吃喷口涌出的微生物，懒到被烫红也不挪窝。', 2, 46);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (172, '纳米修复虾', '会啃食金属锈迹，工作认真，但偶尔把鱼钩当锈斑啃断。', 2, 45);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (170, '生态样本箱鱼', '透明腹腔困着外星微生物，像移动水族馆，但常漏水。', 2, 45);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (167, '能量电池鳗', '存微量电能，接触时轻微酥麻感，能给手表续命5分钟。', 2, 45);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (165, '光学迷彩斗鱼', '启动伪装像块时像块模糊马赛克，但水波一荡就露馅。', 2, 44);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (164, '环境调节锦鲤', '微调水温±1℃，耗能巨大，游一会儿就瘫倒冒烟。', 2, 44);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (163, '声呐探测鳐', '发射声波测绘地形，但反馈图像常扭曲成抽象画。', 2, 44);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (121, '诅咒比目鱼', '钓上的人当晚一定会做一个非常无聊的梦，醒来记不得内容，但隐隐觉得吃过亏。', 2, 43);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (118, '地脉鲷鱼', '贴着河床游能感到地下水脉走向。老人钓它来找井，找出来的井八成是干的。', 2, 43);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (117, '风语者鲈鱼', '鳃总张开一点点，说是在听风。大风天它从不咬饵，它说那阵风不对。', 2, 42);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (116, '寒冰鲑鱼', '身上的薄冰是从体表渗出去的，越冷越精神；水温一升，它反而蔫得很快。', 2, 42);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (115, '火焰鲤鱼', '鱼缸里养着它，缸壁的水会常年微温，不烫，刚好够泡个茶。', 2, 42);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (114, '月光鲶鱼', '白天就是条普通鲶鱼，月夜里它的胡须会自己飘起来，指向月亮的位置。', 2, 41);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (40, '无须鳕', '深水鱼类，作为独立的无须鳕科的下场，仍然是被做成鱼排。', 2, 41);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (39, '青鳕', '常见的食用鱼，肉质白色。肉嫩味美的它常常去餐桌上做客。', 2, 40);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (38, '黑线鳕', '背部有明显的黑色侧线。这条黑线是它的“单线加长条纹码”。', 2, 40);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (37, '比目鱼', '眼睛长在同一侧，身体扁平。它眼中的世界是否更加立体呢，只有它才知道了。', 2, 40);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (35, '牛头鱼', '头大嘴宽，常见的小型鲶鱼。长得像牛头，性格也温和？', 2, 39);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (33, '莓鲈', '北美常见的两种太阳鱼，分黑莓鲈和白莓鲈。跟水果没关系哦。', 2, 39);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (32, '蓝鳃太阳鱼', '北美常见的太阳鱼，色彩鲜艳，是水中的一道彩虹。', 2, 38);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (31, '河鲈', '广泛分布的淡水掠食性鱼类。水域中的小霸王，钓鱼人的好目标。', 2, 38);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (30, '螃蟹', '横行霸道的甲壳生物。小心它的钳子，小心完了之后就能得到鲜美的肉和黄。', 2, 38);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (29, '小丑鱼', '和海葵共生，颜色鲜艳。在某个片场似乎是人见人爱的大明星。', 2, 37);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (28, '河豚', '生气时会鼓成一个球，可能有毒！美味与风险并存，非专业勿试。', 2, 37);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (23, '鳊鱼', '体型侧扁，味道不错。扁扁的身材，鲜美的味道。', 2, 36);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (22, '鲢鱼', '头部较大，滤食性鱼类。头大聪明？不，头大好喝汤。', 2, 36);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (21, '鲤鱼', '据说能带来好运。钓到它，今天运气一定不错。毕竟鲤鱼可好吃了。', 2, 36);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (444, '醉丹鳉', '误食过几粒丹渣，从此走路都像踩着云。', 2, 35);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (20, '草鱼', '喜欢吃草的淡水鱼，素食主义者，但肉质一点也不素。', 2, 35);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (443, '丹渣鲫', '在丹炉废水沟里捡渣吃长大的，身上有一股说不清的药香。', 2, 34);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (442, '缩骨鲦', '能把骨头缩到比鱼鳃还小，被钓起的时候已经把自己拧成了一团。', 2, 34);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (441, '啸石鳗', '听说能用尾巴敲石头唱歌，但那歌没人爱听。', 2, 34);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (440, '鸣山小蛙', '半鱼半蛙，叫声能引来山间回响，但只能引来三声。', 2, 33);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (439, '双瞳鲈', '一只眼黑一只眼金，山中老人见了都要绕道走。', 2, 33);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (438, '三尾小鳉', '来自山海经记载边角的小异兽，三条尾巴还没习惯，游起来打架。', 2, 32);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (437, '寒铁鳉', '灵气铁矿水里养出来的，冷冰冰一身硬鳞，敲起来叮当响。', 2, 32);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (436, '矿尘鲷', '鳃里常年掉灵气矿粉，呼吸都带着一股金属味。', 2, 32);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (435, '嗜灵小蟹', '钳子上有矿石结晶，咬钩时火星四溅，吓得钓鱼人以为撞鬼了。', 2, 31);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (434, '矿脉鳗', '喜欢绕着灵矿脉游，能闻出哪一截矿脉灵气最浓。', 2, 31);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (433, '灵矿苔鲫', '鳞下藏着一层灵气矿苔，刮下来能当便宜的灵药。', 2, 31);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (432, '镇宅鳔虾', '一张镇宅符化进了它的鳔，所以它走到哪都被当镇宅之宝供着，但其实它只是怕水流。', 2, 30);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (431, '失败护身鱼', '本来该贴在某个倒霉鬼背上当护符的，结果咒错了，化成了鱼。', 2, 30);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (430, '残咒鲈', '身上飘着一缕未散尽的咒文，离水就慢慢淡去。', 2, 29);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (429, '余墨鳉', '道士洗笔的水里游出来的，体色乌黑发亮。', 2, 29);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (428, '错符鲦', '据说是被一张写错字的符箓化出来的，鳞片上还残留着歪歪扭扭的笔画。', 2, 29);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (370, '滤水鲫', '终生待在污水循环口附近，嘴巴常年咬着一截不肯放下的过滤棉。', 2, 28);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (369, '排污管鳗', '体表覆盖一层奇怪油膜，但身体本身倒是干净的，靠吃管道里的合成淤泥长大。', 2, 28);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (368, '涂层共生虾', '壳面像被反复刷过几层漆，仔细看是无数纳米机械虫在轮班补漆。', 2, 27);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (367, '修复菌鲶', '受伤了不会流血，会冒一缕银灰色尘雾把伤口封上，看着倒像在抽烟。', 2, 27);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (366, '残光鲷', '鳞片上还有一点出厂时灌进去的辉光，离水后会一分一分地黯下去。', 2, 27);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (365, '微电池鳉', '鳃后嵌着一颗黄豆大的能量囊，触碰会让你的指尖发麻片刻。', 2, 26);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (364, '备用器官鲷', '体内多了一组没用上的器官，研究员标注“暂留观察”就走了，再没回来过。', 2, 26);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (363, '双头错版鲈', '一头吃食一头说不饿，永远在内部投票表决要不要咬钩。', 2, 25);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (362, '缝合鳕', '体侧有一道明显的拼接缝，两半身体明显是不同的物种，但居然合得来。', 2, 25);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (275, '枯井蛙', '会在呼吸孔里吼出雷鸣回声威慑捕食者，实际体型不如拇指大。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (274, '沙钱蟹', '背壳长成古金币花纹，是收藏家的最爱，直到被发现是活蟹。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (273, '滚草团鱼', '这种鱼在退潮的海滩上会蜷缩成球随风滚动，常被误认成风滚草踢飞。但沙滩上怎么会有风滚草？', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (272, '水囊鱼', '体内储水腔占身体60%，挤一挤能喝到半口水，但咸涩如泪。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (270, '海市蜃楼虾', '透明躯壳折射光线，远看像块晃动的肥肉，近看嘛……就是虾。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (266, '沙漏蜥蜴鱼', '背鳍进化成沙漏形状，每次翻身都会精准地计时30秒……但对钓鱼毫无帮助。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (212, '熔岩苔藓龟', '背着火山苔藓的微型龟，爬速堪比凝固岩浆。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (206, '荧光厌氧鱼', '厌氧发光菌覆盖全身，绿光幽幽如鬼火，一接触氧气就熄灭。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (162, '荧光外星藻球', '无害粘液球，夜光如廉价霓虹，一捏就瘪。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (156, '太阳能充电鱼', '背嵌光伏板，晴天慢充，阴天变砖头鱼。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (155, '全息投影小鱼', '投射劣质3D广告：“特价浮游生物！” 信号差时满屏马赛克。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (113, '彩虹鳟鱼', '鳞片本身是灰白色的，那道彩虹只在它觉得自己被欣赏时才浮现出来。', 1, 8);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (630, '烤盘鲫', '浅滩里晒得暖暖的小鱼，肉嫩得用手一捏就熟。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (629, '旱地小鳗', '钻沙比游水快，钓它得在它钻进沙里之前提竿。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (628, '沙粒蝌蚪', '沙质雨后会突然冒出来，三天后变成沙漠青蛙跳走。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (627, '仙人球小蟹', '壳上长着一圈短刺，被踩到也只是有点扎脚。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (626, '沙鼠虾', '个头比指甲大不了多少，在沙面上像跳蚤一样乱蹦。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (625, '干枯小蛙', '旱季时会缩成土色硬块埋在沙里，下雨那天会瞬间复活。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (624, '风蚀贝', '壳上的纹路是被风沙打磨刻出来的，不是天生的。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (623, '漠泉小鳉', '沙漠绿洲泉眼里的银白小鱼，离开泉水活不过半天。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (622, '沙地小蜥', '体型只有指节大，能从指缝间溜走，鱼缸得加盖才不会跑。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (525, '古坛苔鳗', '喜欢在古祭坛遗址下蹭青苔，蹭出来的苔会发淡淡的紫光。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (524, '残纹鲦', '身上的花纹像被人擦过一半的图腾，擦它的人早不在了。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (107, '迷你海马骑士', '胸口一块铠甲状的硬鳞，巴掌大的它一辈子在水草间巡游，像在守某样东西。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (19, '胡瓜鱼', '体型细长，有一种特殊的黄瓜味。是鱼还是瓜？这是个问题。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (16, '斑点鱼', '尾鳍基部有个明显的黑斑。这大概是它的专属纹身。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (15, '大西洋黄花鱼', '能发出类似蛙鸣的鼓噪声。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (14, '银鲈', '沿海常见的小型银色鱼类，它只错在鲜嫩味美。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (11, '罗非鱼', '繁殖能力很强，适应性好，随便吃。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (6, '海虾', '比淡水虾稍大，但还是不够吃。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (5, '小黄鱼', '体色金黄，常见食用鱼，经常出现在烧烤摊。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (4, '沙丁鱼', '成群结队的小型海鱼，与你最常见面的地方其实在罐头里。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (3, '小虾', '常见的水底生物，除了小了点，谁会不喜欢呢？', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (2, '泥鳅', '滑溜溜的小家伙，险些从你手中滑走。', 1, 7);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (523, '碑底小鱼', '在某块沉海古碑底下生活，鳞片上隐约印着碑文的反字。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (522, '缝隙鳉', '总爱钻进海底古老遗迹的石缝，身体细得能穿过指节。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (521, '暗鳃鲈', '鳃缝是深褐色的，但血是黑的，这种黑跟正常鱼血凝固的黑不一样，你最好别问。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (520, '默幼鲶', '这条小鱼一辈子没发出过任何声音，深渊里的孩子都不爱说话。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (519, '缘深鲦', '待在深渊和正常海域的交界处，长得也是介于两边之间的样子。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (518, '渊泥鳉', '来自深渊浅缘的小鱼，鳞色像被水煮黑过。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (517, '深渊小目', '一只眼睛大一只眼睛瞎，深渊里出生的婴儿都这样。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (516, '漂梦小鲶', '它的胡须会朝着白天没有方向的“虚空”方向飘，那大约是某人梦的方向。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (515, '残梦虾', '偶尔会突然停下，像是想起了某个不属于自己的梦。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (514, '飘梦鲦', '总跟着不知谁的梦游过，梦走它就走，梦醒它就停。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (513, '半梦小鳉', '一半在水里游一半似乎在梦里游，你永远抓不准它现在到底在不在。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (512, '梦泡鱼', '周身浮着几个淡灰色的小泡，据说每个泡都是别人睡梦里溢出来的碎片。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (511, '浊水鲶', '喝惯了浊水，反倒清水里活不长。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (510, '漂沫小蟹', '总在污泡沫里打滚，钳子上挂着一层挥之不去的肥皂膜。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (509, '灰渍鳉', '通体泛着洗不掉的灰，连水都嫌它脏。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (508, '锈眼小鲈', '一只眼睛里嵌着锈红色的斑，看东西据说会偏向哪一边。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (507, '油膜鲦', '总在污水浮油里钻来钻去，鳞片闪着不健康的虹彩。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (427, '福泉小鲫', '据说在福泉里养过的鱼会带福气，至于真假，你尝尝就知道了。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (426, '玉露虾', '体表常年挂着一层晶莹水珠，碰一下就消散，再凝一颗。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (425, '灵泉鳉', '终生不离灵泉一寸，离水后会一边漏出泉气一边变得灰扑扑。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (424, '调皮鲇', '性子贪玩，喜欢顶钓鱼者的浮漂玩，是修仙界的熊孩子。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (271, '化石蝌蚪', '休眠于岩层中的活化石，遇水苏醒乱跳，半小时会后变回石头。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (269, '响尾蛇鳗', '尾部鳞片摩擦发出嘶嘶声，吓跑天敌……和鱼饵。', 1, 6);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (268, '日光浴龟', '白天摊平如烤饼一样吸收热量，夜晚靠余温游动。懒到被海砂埋了也不挣扎。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (267, '仙人掌刺鲀', '吸入空气膨胀成球，体表硬化刺伪装仙人掌。递给骆驼的话被误啃率高达80%。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (211, '压力适应水母', '身体压缩如扁罐头，减压后膨胀三倍，然后炸成粘液。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (210, '矿渣比目鱼', '拟态成冷却熔岩渣，游动时像块会抽搐的焦炭。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (209, '沸水小虾', '在90℃热泉里蹦迪，一离水就会变成“熟虾刺身”。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (208, '地热浮游团', '高温凝胶状聚合体，吞食矿物微粒，捏起来像烫手的史莱姆。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (207, '硫磺结晶鱼', '体表分泌硫磺壳，形如行走的黄水晶，可惜易碎又廉价。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (205, '气泡熔岩蟹', '甲壳布满气孔，高温时喷出滚烫气泡，威力仅够吓跑小虾米。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (204, '黑烟囱蠕虫', '寄生在火山烟囱壁，滤食热液微生物，长得像烧焦的意大利面。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (203, '耐热蝌蚪菌', '像烧焦的蝌蚪，靠啃食硫磺晶维生，离开发热区会立刻冻僵。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (161, '迷你探矿鱼雷', '小号勘探器，只会嘟嘟响并报告“此处有泥沙”。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (160, '反重力水母', '飘忽不定像漏气气球，一戳就翻滚逃窜。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (159, '合成口粮鱼', '实验室批量生产的蛋白块鱼，味道像过期电路板。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (158, '数据蝌蚪', '闪烁二进制微光，试图联网但信号弱到只能发“404”。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (157, '生锈螺丝蟹', '会捡废螺丝当壳，走两步掉零件，叮当作响。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (154, '纳米清洁鱼', '吞食微生物垃圾，效率低下，常被水藻困住，不得不发送求救信号。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (153, '故障助手机器鱼', '迷你机械鱼，号称能导航，却总撞水草卡死机。重启键在鱼肚子上。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (112, '巫师学徒鱼', '想给自己变出第二条尾巴，每次都变出别的，目前最像样的是第二个鳃盖。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (111, '地精石斑鱼', '地精掉过的旧硬币只要被它捡到，三天后能在它腹腔里找回，脏一点的那种。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (110, '精灵飞鱼', '精灵教它飞。它学了三百年，到现在还是只会扑通扎进对岸水里。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (109, '矮人钓鱼鱼', '矮人们说这种鱼蠢到能连续上钩三次都不长记性。有时候确实能。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (108, '气泡金鱼', '吐的气泡要漂上水面才破，破的时候有极轻的「叮」一声，得静下来才听得见。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (106, '魔法浮萍鱼', '啃过太多魔法浮萍，鳞片每隔一刻钟换一种颜色，连它自己也猜不准下一种。', 1, 5);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (423, '偷丹小鱼', '从洞府里偷过几粒丹渣的，嘴角还沾着一点药粉。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (422, '学语鳉', '你说什么它学什么，但永远学不全，听着像吞了水的回声。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (421, '妖灵小鲶', '胡须比同族长出几寸，自以为是修仙界的元老。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (420, '半化鳞鲤', '偶尔会试图吐出一句人话，但每次都吐成水泡。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (419, '引气小鲦', '据说能为药材引气，但其实它只是喜欢围着药味打转。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (418, '灵泥蚯虾', '翻药田泥时挖出来的，沾着一肚子药渣。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (417, '安神鲫', '据说肉性温和能安神，吃多了就会昏睡过去。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (416, '药圃锦鳉', '在药田水沟里游来游去，被采药人当宠物一样养着。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (415, '灵参伴鳞', '总绕着灵参根游，沾了一身参味，炖汤最香。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (414, '露水鳉', '据说只喝晨露，但被你钓起的时候嘴里全是泥沙。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (413, '飞流虾', '习惯逆着瀑布游，钓上来的时候它还以为还在登天。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (105, '会唱歌的河鲈', '总在水草丛深处低声哼唱，调子像哪首民歌走样了一半，靠近时它会闭嘴。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (104, '发光小精灵鱼', '夜晚发出萤火虫般的光，只够照亮自己的鼻子', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (18, '凤尾鱼', '常被用来制作鱼干或罐头。罐头里的常客，鲜味被封存其中。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (17, '食蚊鱼', '以蚊子幼虫为食，体型微小。蚊子的天敌，虽小却有大作用。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (13, '鮈鱼', '生活在水底的小型鲤科鱼，以小钓大的机会！', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (12, '鲦鱼', '溪流中常见的小型杂食鱼，希望你钓起来的不是它们的首领……', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (10, '普通石头', '就是一块普通的石头，沉甸甸的，伤害1D3。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (9, '缠绕的水草', '一团湿漉漉的水生植物，缠上了你的鱼线，解去吧。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (8, '生锈的铁罐', '被水泡得不成样子了，依然恪尽职守，能装水。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (7, '破旧的靴子', '谁把靴子扔水里了？还能穿吗？', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (1, '小鲫鱼', '一条非常常见的小鱼，孤苦伶仃。只能炖汤。', 1, 4);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (412, '灵气小鲫', '灵气浓的水里养出来的，比凡间鲫鱼要瞪人一点。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (411, '春溪鲦', '只在春溪解冻后冒头，一冬都在睡。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (410, '苔石鳉', '总爱蹭青苔石头，蹭得鱼身都绿了一半。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (409, '涧底银鳞', '山涧清流里的小鱼，鳞片亮得像泡过山泉。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (361, '余温小鲫', '体温常年保持38度，摸起来像刚煮过的肉丸，但还活蹦乱跳。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (360, '暖管鳗', '只在工厂废水排口附近活动，水凉了就僵成铅笔形。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (359, '染色失败鱼', '每隔一小时换一次颜色，像走丢的霓虹招牌，自己都搞不清原色。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (358, '培养液鳉', '闻起来一股琼脂味，至今还以为水族箱外面是一片实验室。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (357, '编号097', '鳃盖上还粘着褪色标签，本来今天该被销毁的，结果它先逃了。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (356, '报错鲽', '体侧不停滚动着红色字符，凑近能看见“E-404”，开发者早跑路了。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (355, '焊点小鲦', '鳞片下嵌着几粒虚焊的金属珠，掉一颗就少一片光。', 1, 3);
INSERT OR IGNORE INTO "fish" ("fish_id", "name", "description", "rarity", "base_value") VALUES (354, '锈鳃机鱼', '半生体的小鱼，鳃片每呼吸一次都咯噔响一下，听着像漏油的闹钟。', 1, 3);

-- table: baits
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (1, '玉米', '很嫩的玉米粒，许多鱼爱吃，不出意外的话坐你隔壁的钓友也爱吃。', 1, '钓鱼成功率+2%', 10, 1, 0.02, 0, 0, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (2, '面包屑', '你买了一大袋钓鱼专用面包屑打窝，在海边拆袋看见隔壁钓友手中一大袋的面包时“嘶”地皱眉。', 2, '钓鱼成功率+4%', 30, 2, 0.04, 0, 0, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (3, '蚯蚓', '普通又好使的万能鱼饵，除了长得有点不敢恭维以外没有缺点。', 3, '钓鱼成功率+5%，稀有度+2%，垃圾减少率+3%', 80, 3, 0.05, 0.02, 0.03, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (4, '钓鱼专用鱼饲料', '工业混合物，原料到底是是什么呢？据说都是鱼喜欢的东西，有面包屑，蚯蚓，玉米等等，收你的是加工费啦。', 4, '钓鱼成功率+5%，稀有度+5%，垃圾减少率+5%', 150, 4, 0.05, 0.05, 0.05, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (5, '浓缩饵砖', '水产实验室压出来的高蛋白饵砖，散发浓郁的海鲜香气；包装很正规，反而让人有点不安。', 5, '钓鱼成功率+10%，稀有度+5%，垃圾减少率+5%，钓鱼CD-10%', 500, 5, 0.1, 0.05, 0.05, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (6, '诱食胶囊', '胶囊会根据水温和盐度缓慢释放诱食剂，说明书写得像药品广告，标题是“！人禁止食用！”。', 6, '钓鱼成功率+10%，稀有度+6%，垃圾减少率+7%，钓鱼CD-20%', 1000, 6, 0.1, 0.06, 0.07, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (7, '微型法阵', '一次性法阵，普通鱼类只是擦肩而过就会被击晕……还没来得及吞。', 7, '钓鱼成功率+10%，稀有度+7%，垃圾减少率+9%，钓鱼CD-30%', 0, 7, 0.1, 0.07, 0.09, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (8, '纳米钩爪', '你的鱼饵一把把鱼给把住了。', 7, '钓鱼成功率+10%，稀有度+6%，垃圾减少率+5%，数量+5%，钓鱼CD-30%', 0, 7, 0.1, 0.06, 0.05, 1, 1.05, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (9, '灵石', '据说在某些人眼里是能被当做货币的硬通货，看起来在鱼这儿也是硬通货。', 7, '钓鱼成功率+10%，稀有度+7%，垃圾减少率+5%，价值+5%，钓鱼CD-30%', 0, 7, 0.1, 0.07, 0.05, 1.05, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (10, '触须', '什么叫你的鱼饵在吃你的鱼？', 7, '钓鱼成功率+10%，稀有度+7%，垃圾减少率+4%，钓鱼CD-30%', 0, 7, 0.1, 0.07, 0.04, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (11, '永燃焰', '鱼钩被包裹在火焰中，说明鱼没活也会咬打火机。', 8, '钓鱼成功率+10%，稀有度+8%，垃圾减少率+11%，钓鱼CD-40%', 0, 8, 0.1, 0.08, 0.11, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (12, '量子成像', '鱼每次移开视线都会观测到不同的鱼饵，以此全自动筛选出鱼的喜好。', 8, '钓鱼成功率+10%，稀有度+8%，垃圾减少率+7%，数量+5%，钓鱼CD-40%', 0, 8, 0.1, 0.08, 0.07, 1, 1.05, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (13, '天道气息', '一缕蕴含天道的气息，但真的被鱼吃了的话它会得道然后来寻仇。', 8, '钓鱼成功率+10%，稀有度+8%，垃圾减少率+8%，价值+8%，钓鱼CD-40%', 0, 8, 0.1, 0.08, 0.08, 1.08, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (14, '梦潮腮瓣', '从梦里漂上岸的半透明腮瓣，离水后仍在一张一合，像是在替谁呼吸。', 8, '钓鱼成功率+10%，稀有度+8%，垃圾减少率+7%，钓鱼CD-40%', 0, 8, 0.1, 0.08, 0.07, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (15, '星陨鳞粉', '星陨之夜从巨鱼鳞片上刮下的银粉，撒入水中非常吸鱼，还会短暂映出不存在的星座。', 9, '钓鱼成功率+10%，稀有度+9%，垃圾减少率+13%，钓鱼CD-50%', 0, 9, 0.1, 0.09, 0.13, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (16, '轨道诱鱼信标', '小型轨道信标会向水面投射诱导频段，鱼群不知道自己为什么靠近，也不知道这东西有没有经过批准。', 9, '钓鱼成功率+10%，稀有度+9%，垃圾减少率+10%，数量+8%，钓鱼CD-50%', 0, 9, 0.1, 0.09, 0.1, 1, 1.08, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (17, '归墟道种', '一粒沉在归墟水脉里的道种，入水后会生出极细的灵根，替你寻找那些本不该被钓起的鱼。', 9, '钓鱼成功率+10%，稀有度+9%，垃圾减少率+9%，价值+10%，钓鱼CD-50%', 0, 9, 0.1, 0.09, 0.09, 1.1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (18, '搏动眼球', '会盯着鱼看的眼球。但如果周围没有鱼，它就会一直盯着你看。', 9, '钓鱼成功率+10%，稀有度+9%，垃圾减少率+13%，钓鱼CD-50%', 0, 9, 0.1, 0.09, 0.13, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (19, '吐息碎片', '晶体化后碎裂成无数碎片的火龙吐息，吓退屈于龙威的弱小鱼类。', 10, '钓鱼成功率+10%，垃圾减少率+30%，钓鱼CD-60%', 0, 10, 0.1, 0, 0.3, 1, 1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (20, '微型黑洞', '用微型黑洞作为鱼饵唯一要小心的事就是随时抓紧鱼竿。', 10, '钓鱼成功率+10%，数量+10%，垃圾减少率+15%，钓鱼CD-60%', 0, 10, 0.1, 0, 0.15, 1, 1.1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (21, '龙蕴结晶', '龙所待过的池子里会形成的结晶，没有鱼能抵抗。（真的不是汗吗……）', 10, '钓鱼成功率+10%，稀有度+10%，数量+10%，钓鱼CD-60%', 0, 10, 0.1, 0.1, 0, 1, 1.1, 1);
INSERT OR IGNORE INTO "baits" ("bait_id", "name", "description", "rarity", "effect_description", "cost", "required_rod_rarity", "success_rate_modifier", "rare_chance_modifier", "garbage_reduction_modifier", "value_modifier", "quantity_modifier", "is_consumable") VALUES (22, '漆黑物质', '它主动黏住了你的鱼线，已经甩不掉了。', 10, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+15%，钓鱼CD-60%', 0, 10, 0.1, 0.1, 0.15, 1, 1, 1);

-- table: rods
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (1, '竹竿', '削片竹+棉线，最朴素的钓竿，新手村大爷送你的那种。如果你说"这都不能算钓竿"，那是因为你还没真正钓过鱼。', 1, 'shop', 100, 1, 1, 0.04, 0, 99);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (2, '玻璃钢钓竿', '工业玻璃纤维杆，便宜耐用，村口便利店和加油站都有售。看着没什么气质，但比竹竿不知道高到哪里去.', 2, 'shop', 300, 1.01, 1, 0.08, 0, 199);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (3, '碳素纤维竿', '现代工艺的结晶，不过还不是巅峰，这种只是性价比好所以卖得最多。', 3, 'shop', 1000, 1.02, 1, 0.12, 0.01, 399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (4, '钛合金多节竿', '钛合金骨架，轻巧又坚韧，可拆卸成数节便于携带。出门远钓的中端选择，把它从拉杆箱里掏出来的那一刻起，旁人就会觉得你是认真的钓鱼佬。', 4, 'shop', 30000, 1.03, 1.01, 0.16, 0.02, 699);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (5, '高模量碳布矶竿', '海钓店挂在墙上当镇店之宝的款式，碳布层数堆到极致以求轻量化和韧性。话说镇店之宝怎么这么轻易就让搬走？', 5, 'shop', 800000, 1.05, 1.01, 0.2, 0.03, 1111);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (6, '电动收线智能竿', '内置力矩感应器和小型马达，号称"能自动应对所有鱼"。注意，它只是把"什么时候收线"代劳了，"什么时候不收"还是你的问题。', 6, 'shop', 6000000, 1.07, 1.02, 0.24, 0.04, 2144);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (7, '触须钓线', '一根没有竿身、只有不停蠕动的触须的"钓竿"。你不太确定到底是你在钓它还是它在钓你，但效果出奇地好，别纠结了。', 7, 'gacha', 1.1, 1.05, 0.28, 0.06, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (8, '黏液浮标杆', '杆身覆盖着不知名的黏液，鱼咬钩时还会渗出更多。第一次握的时候你想吐，第二次握的时候你麻木了，第三次握的时候你开始好奇这是不是某种生物的体液。', 7, 'gacha', 1.09, 1.08, 0.28, 0.04, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (9, '神经传导钓竿', '竿身嵌入未知生物的活体神经，传导着水下的搏动让你"听见"鱼的存在。顺手让你做了几个噩梦。', 7, 'gacha', 1.13, 1.02, 0.28, 0.05, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (10, '桃木伏波竿', '道士伏水驱邪用的桃木杆，鱼来不犯主人；只是这"主人"的定义有点模糊，鱼好像觉得是它们自己。', 7, 'gacha', 1.12, 1.04, 0.28, 0.04, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (11, '紫竹仙人钓', '传说是某位谪仙人下凡时随手插在地上的紫竹，几百年后被钓鱼佬挖出来当竿用。能勾来灵性鱼，但灵性鱼会跟你讲道理，你也得做好辩论的准备。', 7, 'gacha', 1.13, 1.05, 0.28, 0.05, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (12, '钓灵符', '持符即竿，化道为线。修士眼里这是工具，钓鱼佬眼里这是玄学；但反正钓得到鱼，那就够了。', 7, 'gacha', 1.11, 1.02, 0.28, 0.06, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (13, '溪语者', '镶嵌月光苔的银桦木竿，竿尖流淌水流纹路的符文；月光的祝福让每次垂钓能有额外收获，一定程度上对稀有生物有吸引力。', 7, 'gacha', 1.1, 1.08, 0.28, 0.05, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (14, '雷云捕手', '使用风暴巨鹰尾羽打造的紫纹钓竿，缠绕静电火花，你感觉麻麻的，鱼也感觉麻麻的。这算不算在电鱼啊？', 7, 'gacha', 1.09, 1.06, 0.28, 0.04, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (15, '古龙鳞竿', '老龙脱落的鳞片缝在杆头，用龙的气息镇压水中之物。你的鱼竿因此散发出一股老龙才有的——怎么说呢，老人味。但鱼好像很受用。', 7, 'gacha', 1.12, 1.04, 0.28, 0.05, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (16, '虫洞投射钓竿', '握柄内置虫洞发生器，能让鱼饵直接出现在深水区，能大幅提升接触稀有鱼类的机会，以及触底的风险。', 7, 'gacha', 1.09, 1.02, 0.28, 0.07, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (17, '纳米修复钓竿', '表面覆盖自修复纳米涂层，被鱼撕裂的钓线能缓慢再生。因此，你和鱼谁先撑不住就完全要看你的水平了。', 7, 'gacha', 1.12, 1.05, 0.28, 0.04, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (18, '量子纠缠钓竿', '钓线由量子纤维编织，当鱼咬钩时，竿体会分裂出虚幻的平行时空投影干扰鱼类（和你的）判断。', 7, 'gacha', 1.1, 1.08, 0.28, 0.05, 4399);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (19, '共生触腕', '表面布满搏动血管的触手缠绕上你的手臂……看起来它可以无限延长，能更加轻松地够到那些居住在深海中的东西，但你时常感觉自己仿佛要被它反向拖入深渊……', 8, 'gacha', 1.15, 1.05, 0.32, 0.07, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (20, '尖细的羊蹄竿', '一根漆黑的又尖又细的羊蹄，断面伸出密麻的触手…你差不多看习惯了。这些触手让你一次性有更大鱼获，但它来者不拒，经常抓到杂鱼。', 8, 'gacha', 1.12, 1.12, 0.32, 0.05, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (21, '黏稠漆黑的羊蹄竿', '这竿羊蹄通体漆黑又黏又滑，竿体还包裹着未蜕尽的胎衣，它似乎在孕育新的钓竿？以你的视界还无法理解。', 8, 'gacha', 1.13, 1.1, 0.32, 0.04, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (22, '诛仙竿', '曾有一柄赫赫有名的仙剑，名为诛仙剑，因诛杀太多修士而染上了邪气，因此被其主人亲手毁掉……它的碎片被重铸成此鱼竿，为的是让它在垂钓过程中修身养性，洗蜕杀气。这便是为什么你拿着它就想抽旁边的钓友的原因了。', 8, 'gacha', 1.16, 1.04, 0.32, 0.06, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (23, '百炼成仙竿', '匠人对自己的作品始终不满意，反复重铸后让此鱼竿诞生了器灵，不过由于是新生的灵，除了自称是鱼竿仙、非常喋喋不休以外什么都帮不了你，也就鱼竿本身的质量确实过硬。', 8, 'gacha', 1.17, 1.05, 0.32, 0.05, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (24, '万竿归宗', '一钩化千万，一杆抵万杆，虽然不能一把拉起千万条，但钓起来的可能性变高了，就是用起来有点累。', 8, 'gacha', 1.15, 1.06, 0.32, 0.06, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (25, '冰晶溯流竿', '寒冰核心锻造的透蓝钓竿，接触水面会凝结霜花…由于寒冷鱼类变得行动迟缓，在被举报污染环境之前，尽全力回本吧。', 8, 'gacha', 1.16, 1.05, 0.32, 0.05, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (26, '龙王骨竿', '传说中某条魔龙的脊椎打磨而成，触感冰冷如同它生前盘踞的王座。挥动时鱼群仿佛感受到龙王的威压，纷纷主动来朝拜。', 8, 'gacha', 1.14, 1.09, 0.32, 0.06, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (27, '古精灵之杆', '由精灵长老亲手雕琢，竿身刻满古老咒文。垂钓时它会发出极轻微的歌声，鱼听了便迷醉而上钩。同一首歌你听久了倒不会迷醉，只会困得想睡觉。', 8, 'gacha', 1.16, 1.08, 0.32, 0.05, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (28, '奇点引擎钓竿', '以模拟黑洞奇点为核心动力，产生引力漩涡吸引范围鱼群。在它吸入沉船残骸之前还是挺好用的。', 8, 'gacha', 1.14, 1.09, 0.32, 0.07, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (29, '时空回流竿', '竿头嵌入时空回溯装置，鱼咬钩的瞬间它会把鱼"拉回"几秒前的位置——就在它差点逃跑的那一刻。物理学家会反对，但鱼不会。', 8, 'gacha', 1.16, 1.04, 0.32, 0.06, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (30, '反物质钓针', '针尖由反物质构成，接触即湮灭，普通的鱼一靠近就完蛋。但偶尔会有鱼因稀有特性而幸存，那就是你今天的好运。', 8, 'gacha', 1.12, 1.04, 0.32, 0.08, 6666);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (31, '神经罗网', '投入神经做成的罗网，沉下啸叫状的人面浮标。它的目标似乎十分明确……那就是永不空军。', 9, 'gacha', 1.19, 1.05, 0.36, 0.08, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (32, '古神舌竿', '某些神伸出舌头变成的钓竿。你不知道这是它的祝福还是它的玩笑，反正你拿着它钓鱼比谁都顺。神已经亲自下场作弊了，鱼还能怎么办？', 9, 'gacha', 1.17, 1.11, 0.36, 0.08, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (33, '捆仙竿', '由捆仙绳改造的鱼竿，甩竿即可自动捆鱼。但本性难移，若是捆到路过修士要记得道歉。', 9, 'gacha', 1.18, 1.09, 0.36, 0.06, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (34, '混沌青莲竿', '世间常道善恶只在一念间，善恶纠缠是为混沌；于混沌中诞生出淤泥而不染，是为青莲。', 9, 'gacha', 1.2, 1.06, 0.36, 0.07, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (35, '巨龙锁链鞭', '由曾妄想锁住龙神的链条的碎片改造而成，现在都还残留着龙神的怒气。鱼见了钩瑟瑟发抖，你也有点瑟瑟发抖，龙神指不定哪天会算错账到你头上。', 9, 'gacha', 1.17, 1.12, 0.36, 0.07, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (36, '破邪竿', '鱼钩闪烁圣光，竿身燃烧着永不熄灭的圣火。第一个用它的人想用来烤鱼，结果发现这火不烫鱼也不烫人，如果你觉得烫，说明你有问题。', 9, 'gacha', 1.19, 1.05, 0.36, 0.07, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (37, '引力收束竿', '竿头能产生局部重力场，扭曲鱼群的游动轨迹直接撞向你的鱼钩。物理学家会指出这不符合任何已知定律，所以它显然不是任何已知定律下的产物。', 9, 'gacha', 1.16, 1.14, 0.36, 0.06, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (38, '量子折叠钓针', '钓针同时存在于多个时空，让它的渔获存在着万千可能性；观测的那一刻才决定结局。请稳定地观测。', 9, 'gacha', 1.18, 1.12, 0.36, 0.08, 9999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (39, '我到底钓到了什么？！', '拉起钓竿的那刻，你忽然意识到你同时钓起了所有鱼、同时没能钓鱼任何鱼、同时钓起了一条杂鱼、同时钓起了一条诡异的鱼、同时……什么叫游戏发生错误将终止客户端？', 10, 'shop', 1.21, 1.12, 0.4, 0.09, 99999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (40, '太上忘情竿', '采用三十三重天冰蚕丝铸成，上钩之鱼皆一副生死看淡、看破凡尘之相。所以也有些失恋的人潜水是为了找这个钩。', 10, 'shop', 1.23, 1.06, 0.4, 0.08, 99999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (41, '巴哈姆特的金鳞爪', '白金龙王巴哈姆特蜕下的一片金属爪鳞，由神圣界的工匠重铸为钓竿。线为金质，钩为银齿，挥动时金鳞流泻圣光。但请记住巴哈姆特是善良龙之神，所以你钓鱼也得讲基本法。', 10, 'shop', 1.22, 1.1, 0.4, 0.08, 99999);
INSERT OR IGNORE INTO "rods" ("rod_id", "name", "description", "rarity", "source", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "success_rate_modifier", "bonus_rare_fish_chance", "durability") VALUES (42, '戴森光束竿', '连接轨道卫星的星能传输系统，钓线为聚焦太阳光束。理论上能钓起恒星物质，但偶尔会因能量过载熔毁鱼钩…以及一些倒霉的鱼…还有一些倒霉的你。', 10, 'shop', 1.2, 1.18, 0.4, 0.09, 99999);

-- table: accessories
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (1, '旧鱼线轮', '二手货，明显是从废品收购站淘出来的，能用就行。', 1, 'general', 1, 1.02, 0, 1.02);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (2, '帆布鱼篓', '普通工艺品，便利店的折扣货架上常年堆着。不漏水、不漏鱼，朴素但合格，钓友的入门标配。', 2, 'general', 1.01, 1.03, 0, 1.04);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (3, '防滑钓鱼手套', '防滑防割的钓鱼专用手套，提竿不易脱手。简单又实用，戴着它你才有钓鱼佬的样子——尽管隔壁那位赤手空拳的大爷比你钓得多。', 3, 'general', 1.02, 1.03, 0, 1.06);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (4, '偏光太阳镜', '滤掉水面反光，资深钓友升级款，戴上后你会发现"诶？这水下原来这么有戏"，也会开始觉得"欸，怎么要买的东西越来越贵"。', 4, 'general', 1.04, 1.04, 0.01, 1.08);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (5, '多功能渔具背心', '多口袋、多挂钩、多腰带的"钓友战术背心"，看起来像要去打仗。但仔细想想，跟鱼这种东西斗智斗勇也确实跟打仗差不多，尤其是当你忘了把面包屑放进哪个口袋的时候。', 5, 'general', 1.06, 1.04, 0.02, 1.13);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (6, '便携式电子鱼探仪', '手持声呐，屏幕上能粗略标记水下深度和鱼群分布。入门级渔获作弊器，但毕竟"知道鱼在哪"和"钓得到鱼"是两回事，它只解决第一个问题。', 6, 'general', 1.08, 1.06, 0.02, 1.18);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (7, '蠕动眼瞳护符', '一颗一直转动注视的眼球，挂在脖子上当护符。你不太确定它是看着鱼还是看着你；但反正没发生别的事，你也没想太多。', 7, 'general', 1.12, 1.08, 0.04, 1.22);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (8, '胎膜手套', '像第二层皮一样贴合手掌的薄膜手套，会渗血。戴着它的手钓鱼有奇效，水里的东西好像把它当成了同类。', 7, 'general', 1.15, 1.12, 0.02, 1.2);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (9, '哀鸣项链', '项链上串着会自己呜咽的小肉块，听起来像是婴儿在哭。鱼听了会受惊，往哪都想躲，然后就躲到了你的鱼钩上。', 7, 'general', 1.1, 1.15, 0.03, 1.21);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (10, '镇魂铃', '挂在腰间的青铜小铃，鱼听见铃声便心境澄明、不再挣扎。也有修士说这铃声其实是镇压死灵的。', 7, 'general', 1.15, 1.08, 0.02, 1.22);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (11, '太极鱼坠', '阴阳调和的玉坠，钓获亦阴阳调和；一半是上品鱼，一半是下品鱼。嗯，总比一半都没有强吧？', 7, 'general', 1.16, 1.13, 0.01, 1.2);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (12, '紫府符纸', '他们都说这是"大能加持过的"，但你怀疑只是普通宣纸盖了个章。当然，加持没加持鱼说了算，鱼似乎挺买账。', 7, 'general', 1.13, 1.1, 0.03, 1.21);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (13, '藤蔓编织鱼篓', '森林德鲁伊培育的活体容器……话是这么说，其实就是用藤蔓编了个鱼篓而已，怎么敢卖十倍价的？！', 7, 'general', 1.1, 1.18, 0.01, 1.2);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (14, '海洋之心', '传说镶嵌于古海王王冠正中的蔚蓝巨钻，承载着他对所有水族子民的最后祝福。王朝覆灭后宝石散落人间，几经辗转才到了你的手上。', 7, 'general', 1.13, 1.09, 0.03, 1.23);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (15, '古龙之息', '采自巨龙巢穴，那里的硫磺晶簇浸透了龙的呼吸。气味浓烈到能让胆小的鱼贩退避三舍，但水里偏有那么些好奇的家伙，会遇到你和你的鱼钩。', 7, 'general', 1.12, 1.1, 0.04, 1.22);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (16, '虚空虹吸戒指', '据说镶砌着微型黑洞碎片，如果是真的的话你大概已经被吸进去了。虽然它好像确实有点像磁铁一样吸鱼，偶尔也会吸到隔壁钓友鱼篓里面的。', 7, 'general', 1.1, 1.16, 0.01, 1.21);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (17, '全息渔获扫描仪', '小型全息投影仪，能实时显示水下分布。几乎能看清每条鱼的眼睛，但其造价仍不足以继承价值判断模组。', 7, 'general', 1.12, 1.09, 0.04, 1.22);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (18, 'AI 鱼饵决策器', '内置小型 AI，会自动调整鱼饵参数让你的钓获最优化。它有时候会发出自言自语般的乱码，也就是所谓的机器学习的"不可解释性"。', 7, 'general', 1.14, 1.09, 0.02, 1.23);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (19, '黄印怀表', '青铜外壳的朴素计时器，它只会擅自进行倒计时，每次倒计时都代表着你有大鱼上钩；但绝对不能亲眼看见倒计时归零的那个瞬间……', 8, 'general', 1.15, 1.12, 0.05, 1.27);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (20, '孕梦珊瑚戒指', '猩红珊瑚枝环成的戒指仍在擅自增殖，持有它的每晚你都在做噩梦，你大汗淋漓地醒来……但不太能记得梦见了什么。', 8, 'general', 1.21, 1.14, 0.02, 1.25);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (21, '同心眼网袋', '装满眨眼的眼球的小布袋，挂在腰间一抖就听见眨眼声"啪啪啪"。鱼很怕被这样注视，所以接近你时会下意识地张大眼睛，然后就惊讶地咬钩。', 8, 'general', 1.16, 1.16, 0.04, 1.26);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (22, '青鸾褪羽', '"清唳惊幽涧，凡鳞拜羽旌"', 8, 'general', 1.21, 1.11, 0.02, 1.26);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (23, '心魔标', '此浮标会在水面扬起你的心魔虚影引诱你提竿，这种压制心魔的修炼颇有益处，但如果提错竿了会发生什么还是别问了。', 8, 'general', 1.17, 1.16, 0.05, 1.24);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (24, '通幽玉佩', '通晓水下灵性的古玉，戴着它你能"感觉"到水底某条特别的鱼正在等你。你说不上来为什么，但它说"是你"。', 8, 'general', 1.18, 1.1, 0.04, 1.27);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (25, '水妖的发丝腕带', '把水妖的头发当腕带，为了保持原味因此无需清洗，发丝间缠绕的不明卵让你感觉恶心，但这个味道似乎还真把鱼给吸引过来了。', 8, 'general', 1.14, 1.22, 0.01, 1.24);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (26, '丰收号角', '传说中的神器，吹响即可吸引鱼群。只有不看使用说明的人会在钓的中途吹，反而把鱼给全部吓跑。', 8, 'general', 1.16, 1.2, 0.02, 1.25);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (27, '圣杯水滴', '装着永流不竭圣水的微缩杯，一滴水能净化一片水域，鱼也开始觉得这片水变好了，纷纷涌来。但你忘了水变好了鱼就更聪明了。', 8, 'general', 1.18, 1.12, 0.02, 1.27);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (28, '时间沙漏钓坠', '有时停效果的神器，能让刚钓上来的鱼就像在水里一样新鲜……嗯？但是直接放鱼篓再放水里不就行了吗？……', 8, 'general', 1.21, 1.1, 0.02, 1.26);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (29, '智械义眼', 'AI 控制的电子义眼，跟你的大脑同步，视域共享后水下任何动静你都看得见。只有播放的广告你怎么也关不掉。', 8, 'general', 1.16, 1.12, 0.05, 1.26);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (30, '暗物质坠饰', '佩戴着一颗"物理外的存在"的坠饰，鱼会下意识地绕道靠近——也就是它们以为自己绕开了你，结果绕到了你的钩上。', 8, 'general', 1.15, 1.18, 0.04, 1.25);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (31, '褪时之颚', '一副交错的不明生物的下颚，颚中有尖柱体形状的舌头诡异地动弹，它总是擅自动起来咬你钓上来的东西，留下一堆圆形的、不会渗血的孔洞伤痕……不知为什么，被咬过的鱼能卖出好价，谁在乎它是不是真的被破坏了。', 9, 'general', 1.2, 1.18, 0.05, 1.31);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (32, '漆黑胎囊', '跳动着的沥青色肉囊，表面凸起有数百颗未睁开的眼球，内部传来胎动般的粘稠挤压声。你不知道它正在孕育什么，只知道把玩起来手感挺有趣，适合钓鱼解压。', 9, 'general', 1.21, 1.23, 0.04, 1.29);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (33, '乾坤鱼篓', '袋内别有洞天，甚至都可以住人了。但进去了还出得来吗？目前为止还没人敢试。', 9, 'general', 1.18, 1.28, 0.03, 1.28);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (34, '太虚引雷钰', '当某些鱼类成长到一定程度，普通的雷已经对它们毫无作用，而此钰可引来附近劫雷为己所用，只需小心别把它们劈渡劫了。', 9, 'general', 1.23, 1.16, 0.06, 1.3);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (35, '龙瞳石', '巨龙留下的眼石，玛瑙般闪烁。佩戴它你能看到水下"龙才能看到的东西"——也就是你不该看到的东西。看了就看了吧，钓鱼要紧。', 9, 'general', 1.21, 1.18, 0.06, 1.31);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (36, '远古德鲁伊种子', '在你包里发芽的远古种子，根系会自己钻出包外伸进水里探鱼。如果你不勤奋地修剪它，再过一周它会把整个钓鱼装备都长成森林。', 9, 'general', 1.19, 1.27, 0.03, 1.29);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (37, '量子断裂腕表', '佩戴它的瞬间，时间在你周围分叉。它向你展示着各种各样的可能性，却让你只能体验到其中一个，所以一切看起来还很正常。', 9, 'general', 1.22, 1.2, 0.05, 1.3);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (38, '维度收纳器', '异维度收纳装置，无视容量限制。你可以一次性把整片海的鱼装进去。但取出来时它会按"被装进去的顺序"排队，所以你本次拿出来的鱼究竟是什么，仍然不可控。', 9, 'general', 1.18, 1.28, 0.04, 1.28);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (39, '千面之皮', '此面可令你化身万物，亦可让你遗忘本质。它会出现在任何事物的可以称得上"脸面"的地方，直到你忘却其原本的样貌。', 10, 'general', 1.27, 1.28, 0.07, 1.31);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (40, '化龙鳞', '当鲤鱼攀上龙瀑、跃过龙门的那一刻，它将忍受生蜕鳞片之苦，以此获得新生，化为真龙。它当时蜕下的鳞片便被称为"化龙鳞"。但凡水族（和龙性恋），皆会被此物吸引。', 10, 'general', 1.27, 1.22, 0.05, 1.31);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (41, '提亚马特的五色金币', '邪龙女王提亚马特宝库中流出的传奇金币，正反面分别铭刻五色龙的爪痕。鱼类送死般吞下你的吊钩，贪婪则逐渐沁入你的内心，这是龙之祝福，也是龙之诅咒。', 10, 'general', 1.24, 1.32, 0.04, 1.31);
INSERT OR IGNORE INTO "accessories" ("accessory_id", "name", "description", "rarity", "slot_type", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "bonus_coin_modifier") VALUES (42, '量子纠缠浮标', '成成对对的的浮浮标标分分置置两两地地，一一方方咬咬钩钩会会同同步步颤颤动动另另一一方方鱼鱼影影。不仅能双倍效率钓鱼，还会播放环大西洋BGM。', 10, 'general', 1.24, 1.32, 0.07, 1.31);

-- table: titles
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (20, 'Lucky☆Star', '在擦弹中获得100倍奖励', '{username}, Lucky☆Star');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (21, '計画通り', '在擦弹中获得200倍奖励', '{username}, 一切尽在掌握!');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (22, '这就是我的逃跑路线！', '在擦弹中获得500倍奖励', '{username}, 这就是我的逃跑路线！');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (23, '超高校级的幸运', '在擦弹中获得1000倍奖励', '{username}, 超高校级的幸运!');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (24, '「 」', '在擦弹中获得1500倍奖励', '{username}, NO GAME NO LIFE!');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (25, '杂鱼~杂鱼~', '在擦弹中获得0.001倍奖励', '{username}, 杂鱼~杂鱼~');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (26, '无敌豌豆大王', '豌豆上贡特级犬粮后获得的特殊职称，具有唯一性、高级性、自定义性与噱头性。', '{name}');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (27, '过路的术士', '向伟大的BOSS献上狗粮，然后获得了一人之下万人之上的名头，说是这么说了，但谁信呢？', '{name}');
INSERT OR IGNORE INTO "titles" ("title_id", "name", "description", "display_format") VALUES (28, '白金之父', '它允许你使用这个称号的唯一原因是你的生杀大权都还掌握在它手里。', '{name}');

-- table: items
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (1, '小钱袋', '装有少量金币的袋子。', 1, '使用：获得 1000 金币。', 0, 1, 'ADD_COINS', '{"amount": 1000}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (2, '中号钱袋', '沉甸甸的钱袋，里面装着不少金币。', 2, '使用：获得 10000 金币。', 0, 1, 'ADD_COINS', '{"amount": 10000}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (3, '大号钱袋', '鼓鼓囊囊的大钱袋，非常重。', 3, '使用：获得 50000 金币。', 0, 1, 'ADD_COINS', '{"amount": 50000}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (4, '神秘钱袋', '会变换重量的神秘钱袋，谁也不知道里面有多少钱。', 4, '使用：随机获得 5000 至 20000 金币。', 0, 1, 'ADD_COINS', '{"min_amount": 5000, "max_amount": 20000}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (5, '巨型钱袋', '仿佛装满了全世界财富的巨大袋子。', 5, '使用：随机获得 100000 至 500000 金币！', 0, 1, 'ADD_COINS', '{"min_amount": 100000, "max_amount": 500000}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (6, '龙之钱袋', '据说是龙看见了也会两眼发光的超大钱袋。', 6, '使用：随机获得 1000000 至 5000000 金币！', 0, 1, 'ADD_COINS', '{"min_amount": 1000000, "max_amount": 5000000}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (7, '擦弹许可证', '官方发放的许可证，允许你今天额外进行1次擦弹。', 6, '使用：今天可用的擦弹次数增加1次。', 0, 1, 'WIPE_BOMB_ATTEMPTS_BOOST', '{"amount": 1}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (8, '归元护符', '成败自有天命，大道自有归途。归元法印，精炼崩毁时会牵回本体残机，虽会折损一重境界，却不至彻底毁坏。', 7, '获得1次基本保护（使用后，进行精炼时自动生效。毁坏时改为降一级并保留本体）。', 0, 0, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "downgrade"}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (9, '晨星祝福徽记', '星辉抵抗灾厄，将毁坏改写为安然无损的失败。', 8, '获得1次精炼保护（使用后，进行精炼时自动生效。毁坏时改判为普通失败，本体保留不降级）。', 0, 0, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "keep"}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (10, '零点保险协议', '一次性量子保险协议，会在精炼判定异常时锁定装备基准态，强制将失败结算压回安全结果。', 9, '获得1次至高保护（使用后，进行精炼时自动生效。任何失败时必改为普通失败，本体保留不降级）。', 0, 0, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "keep"}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (11, '鱼甄选交换凭证', '鱼甄选回收部发放的统一回收货币，用于证明你的研究资质。', 6, '可用于兑换区域通行证。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (12, '鱼光临海域通行证', '由“鱼光临”渔具有限公司发放的一次性通行证，持有此证将被允许进入受其管辖的海域。', 5, '凭此证可进入鱼光临海域。', 100000, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (13, '鱼光临养殖区通行证', '另一张一次性通行证，据说养殖的鱼类因为活得太滋润导致大量繁殖，他们才迫不得已开放出来让人钓。', 6, '凭此证可进入鱼光临养殖区。', 500000, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (14, '全自动工厂污染区域通行证', '你被允许前往该海域的放行理由是能通过钓鱼净化水质。', 7, '可凭此证可进入污染区域。', 0, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (15, '化龙碎片', '化为龙的鲤鱼褪下的残壳碎片。', 7, '可凭此碎片登上龙瀑之巅。', 0, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (16, '千面碎片', '千百种生物皮肤的细小碎片。', 7, '可凭此碎片靠近深渊漩涡。', 0, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (17, '龙窟金币', '因沾染到龙息，有些许融化的普通金币。', 7, '可凭此碎片踏入龙之洞窟。', 0, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (18, '海峡地图', '乱开船乱开车可找不到大家常说的入门海峡在哪。', 5, '可永久进入特定钓鱼区域。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (19, '鱼光临海域通行证（终身VIP）', '本公司海域将永远为您开放！招牌里还会写上您的名字！您是我们的神！把钱给我们！', 6, '可永久进入特定钓鱼区域。', 5000000, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (20, '鱼光临养殖区通行证（VIP客户专供）', '其实原本用另外一张终身VIP证就可以去的…但上面临时又推出了一种通行证……没想到真的会有人买的大嘴巴员工（第二天被开了）如是说。', 7, '可永久进入特定钓鱼区域。', 10000000, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (21, '全自动工厂污染区域通行证（时空错乱）', '这里究竟是未来，还是以前？你唯独能确信的就是这里并非现在。', 10, '可永久进入特定钓鱼区域。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (22, '化龙碎片（磨砺锋芒）', '鲤鱼化龙时，被龙瀑打磨锋利的鳞片碎片。即可伤及自身，亦可割开瀑布；若惧怕伤痛，则无法凭此鳞逆流而上。', 10, '可永久进入特定钓鱼区域。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (23, '千面碎片（血液凝固）', '被凝固的血液粘在一起，忘记了自己究竟是谁；再也无法分开的千种脸面的碎片。', 10, '可永久进入特定钓鱼区域。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (24, '龙窟金币（龙息淬炼）', '被龙息融化千万枚后才能淬出的一枚，其滚烫余温至今都还未散尽。', 10, '可永久进入特定钓鱼区域。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (25, '高级犬尾草冻干狗粮', '献给某些生物即可获得自定义专属称号。', 9, '持有该物品并想办法告诉它你想要的称号，静候神秘生物前来回收即可。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (26, '科考许可证（探险）', '由鱼寻思鱼类进化研究有限公司发放的科学考察许可证，他们的业务覆盖是不是有点太广了…', 7, '可发起探险级科考活动。', 1000000, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (27, '科考许可证（征服）', '对鱼光临的科研团队而言，稳定的特定鱼类获取渠道是非常重要的。仅发放给积累了一定科考实绩的钓鱼佬。', 8, '可发起征服级科考活动。', 0, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (28, '科考许可证（圣域）', '传闻中的巨型科研团队所需的巨量特定鱼类只有极巨的钓鱼佬团队才能完成的巨难的科考任务。', 9, '可发起圣域级科考活动。', 0, 1);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost") VALUES (29, '科考通行证', '要想加入科研团队的话，必须持有的证件。你感觉被他们两头赚了。', 6, '可加入任意科考活动。', 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (30, '称号·鱼甄选CEO', '鱼甄选只把这名号颁给交付过珍品的客户。它不折算凭证，不打折，不找零，没权力没薪水没持股，只证明您确实见过大场面。', 9, '使用后获得称号：鱼甄选CEO', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (31, '称号·观测锚点', '为便于运输免费提供鱼类隔离舱，但无法保障碳基肢体的时空连续性。回收价将视当前维度稳定性收取稳定税与观测费。', 9, '使用后获得称号：观测锚点', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (32, '称号·万机之神', '回收目标：自成长AI-WL-GQ型；拟态破解方程式：量子筛选；冲突损毁补贴：无；交换品项：荣耀。', 9, '使用后获得称号：万机之神', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (33, '称号·星际收藏', '文明墓碑、恒星雏形、引力异常体、熵增残响。科研与收藏价值极高。提交时请隔离存放。', 9, '使用后获得称号：星际收藏', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (34, '称号·生态武装·维度防线', '某些文明建造全自动化工厂阻拦外敌的可能性，由该类可能性构成的多种时间线无法直接观测。感谢您的帮助，该项目名将作为名号转让。', 9, '使用后获得称号：生态武装·维度防线', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (35, '称号·天地劫火', '集炎火为灵之生命，热浪蒸腾，海水沸响，自成一座微缩的暴怒天地。', 9, '使用后获得称号：天地劫火', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (36, '称号·一方霸主', '霸主生灵虎视蠢动，如今在争夺残骸的大战中交汇。', 9, '使用后获得称号：一方霸主', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (37, '称号·寻龙冢', '曾有一缕不灭残魄，以魂灯盗寿命，以断剑斩仙泪。寻龙之途遥遥，迷失永无天日。', 9, '使用后获得称号：寻龙冢', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (38, '称号·寻天道', '何为道？何为天道？不过万物，不过你我。', 9, '使用后获得称号：寻天道', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (39, '称号·存在与不存在之物', '那些只不过是尘埃的鱼类，堆积成了通往深渊的阶梯。', 9, '使用后获得称号：存在与不存在之物', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (40, '称号·别看了。', '别看了。', 9, '使用后获得称号：别看了。', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (41, '称号·吞噬万物', '被死有余辜之物吞噬，然后大汗淋漓地醒来。', 9, '使用后获得称号：吞噬万物', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (42, '称号·创造万物', '那是起源者，又或只是破坏者？', 9, '使用后获得称号：创造万物', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (43, '称号·白金之剑', '此称号证明你的鱼竿将为善龙神巴哈姆特而挥动，从此与五色龙种不共戴天。', 10, '使用后获得称号：白金之剑', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (44, '称号·五彩之爪', '此称号证明你的鱼竿将为邪龙神提亚马特而挥动，从此与金属龙种不共戴天。', 10, '使用后获得称号：五彩之爪', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (45, '称号·至高妖精', '此称号证明你的鱼竿将为妖精王而挥动，从此……开始看善邪龙打架的好戏。', 10, '使用后获得称号：至高妖精', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type") VALUES (46, '称号·元素后裔', '此称号证明你的鱼竿将为……算了，四元素都还打得不可开交呢。', 10, '使用后获得称号：元素后裔', 0, 1, 'GRANT_TITLE_TBD');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (47, '星屑', '金币被投入黑洞后被压缩再吐出的微光碎片，边缘仍残留着不稳定的数据噪声。', 6, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (48, '星核', '钻石在极端引力与高能压缩下凝成的核心结晶，内部封存着一段尚未熄灭的恒星脉冲。', 8, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (49, '道屑', '金币在大道流转时化为的一缕残痕，细若尘埃，却仍隐隐映照天机。', 6, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (50, '道晶', '钻石被道痕凝练、灵机内敛所成的晶体，通体澄澈，却有万千法则在其中沉浮流转。', 8, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (51, '梦屑', '金币从深渊归来后剩下的一点残渣，既是灰尘，亦是尚未凝固的低语。', 6, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (52, '梦核', '钻石被层层幻梦浓缩拉伸后形成的不祥核心，深处埋着一只尚未睁开的眼睛。', 8, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (53, '龙屑', '金币在跨越位面时会融化为细小碎片。由龙息、圣泉与秘法余波共同沉淀。', 6, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable") VALUES (54, '龙晶', '钻石在漫长岁月中被龙威、圣辉与元素潮汐反复淬炼后诞生的结晶。', 8, '用于兑换特殊装备。', 0, 0);
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (55, '深潜门票', '进入区域七时会被克苏鲁深潜系统自动消耗，用于开启当日深潜。', 6, '进入区域七开始钓鱼时自动消耗，开启一次当日深潜。', 0, 1, 'NONE', '{}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (56, '低语之露', '冰凉如夜潮的露滴，入口后理智会被勉强缝回一点。', 6, '使用后恢复 5 点 SAN，不会超过当前上限。', 0, 1, 'ADD_SAN', '{"amount":5}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (57, '古旧瞳孔', '像鱼眼又像星眼的干瘪器官，被它看过的人会多承受一点真相。', 8, '使用后永久提升 1 点 SAN 上限。', 0, 1, 'ADD_MAX_SAN', '{"amount":1}');
INSERT OR IGNORE INTO "items" ("item_id", "name", "description", "rarity", "effect_description", "cost", "is_consumable", "effect_type", "effect_payload") VALUES (58, '协议重写芯', '重写当前觉醒协议的稀缺芯片。使用后仅清空觉醒协议，不退还科研点与分支等级。', 8, '用于 /重写协议 或科幻页面重置当前觉醒协议。', 0, 1, 'NONE', '{}');

-- table: fishing_zones
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "requires_pass", "fishing_cost") VALUES (1, '区域一：新手港湾', '刚买到人生第一杆钓竿的人常被推荐的钓点，只能钓到寻常鱼类。', 500, 8, '{"rarity_distribution": [0.6, 0.3, 0.08, 0.02, 0]}', 1, 0, 10);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (2, '区域二：入门海峡', '积累了一定钓获后就会被推荐来这里，据说偶尔能钓到不同寻常的鱼。', 1500, 0, '{"rarity_distribution": [0.4, 0.3, 0.2, 0.09, 0.01, 0]}', 1, 18, 1, 30);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (3, '区域三：鱼光临海域', '被鱼光临渔具有限公司控制的海域，需要从他们那购买通行证才可以进入。该死的资本。', 3000, 0, '{"rarity_distribution": [0.3, 0.2, 0.28, 0.17, 0.05, 0]}', 1, 12, 1, 100);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (4, '区域四：鱼光临海域-VIP专属区域', '为VIP客户开放的特殊区域，资本的大手养殖着一些特殊的鱼类。钓起的鱼最终还是卖给了他们公司，你也分不清到底是你赚了还是他们赚了。', 5000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.18, 0.0695, 0.0005]}', 1, 13, 1, 300);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (5, '区域五：全自动工厂污染区域', '被久远的工业自动化群排除的污水污染得不成样的海域，工厂至今也还在全自动运作；有一些独特的鱼生活在这里。', 10000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, 14, 1, 1000);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (6, '区域六：云雾缭绕的龙瀑之巅', '传说中鲤鱼化龙之地，此地位处极高，又冷又缺氧，但灵气充裕，修行之鱼会在此停留。', 10000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, 15, 1, 1000);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (7, '区域七：莫可名状的深渊之底', '海域中凭空出现的神秘巨大漩涡，宁静得就像寻常海面一般。一些奇特的鱼会在此出没，也不知它们是否是遭到漩涡影响。', 10000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, NULL, 0, 1000);
INSERT OR IGNORE INTO "fishing_zones" ("id", "name", "description", "daily_rare_fish_quota", "rare_fish_caught_today", "configs", "is_active", "required_item_id", "requires_pass", "fishing_cost") VALUES (8, '区域八：空气沸腾的龙之洞窟', '巨大的火山洞窟中，深不见底的地下水池，洞窟深处仿佛连空气都在沸腾翻滚，一些特殊的鱼出没于此地。', 10000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, 17, 1, 1000);

